I18N.register("pt", {
  q: {
    "TPR1_01": ["O que vem a seguir? ◇, ◇◇, ◇◇◇, ◇◇◇◇, ?", "Conte os diamantes em cada etapa.", ["◇◇◇◇◇", "◇◇◇", "◇◇◇◇", "◇◇"], "Um losango é adicionado a cada passo: 1, 2, 3, 4, então há 5 losangos."],
    "TPR1_02": ["O que vem a seguir? A, B, C, D, E, ?", "Pense na ordem das letras do alfabeto.", ["F", "G", "D", "A"], "São letras consecutivas do alfabeto; depois de E vem F."],
    "TPR1_03": ["O que vem a seguir? 1, 2, 3, 4, 5, ?", "Cada número aumenta no mesmo passo.", ["6", "7", "5", "8"], "Cada número aumenta 1, então depois do 5 vem o 6."],
    "TPR1_04": ["O que vem a seguir? 2, 4, 6, 8, ?", "Observe a diferença entre números consecutivos.", ["10", "12", "9", "11"], "As etapas são 2 por 2. Depois de 8, o próximo número par é 10."],
    "TPR1_05": ["O que vem a seguir? A, B, A, B, A, ?", "Repare no padrão que alterna.", ["B", "A", "C", "D"], "O padrão alterna A e B sem parar; depois de A vem B."],
    "TPR1_06": ["O que vem a seguir? □, □□, □□□, ?", "Conte os quadrados em cada etapa.", ["□□□□", "□□", "□□□□□", "□□□"], "Um quadrado é adicionado a cada etapa: 1, 2, 3, então seguem 4 quadrados."],
    "TPR1_07": ["O que vem a seguir? Z, Y, X, W, ?", "O alfabeto anda para trás.", ["V", "você", "X", "T"], "As letras andam para trás no alfabeto: Z, Y, X, W, V."],
    "TPR1_08": ["O que vem a seguir? 10, 20, 30, 40, ?", "Cada número aumenta no mesmo passo.", ["50", "45", "60", "55"], "As etapas vão de 10 a 10. Depois de 40, o próximo termo é 50."],
    "TPR1_09": ["O que vem a seguir? 3, 6, 9, 12, ?", "Cada número aumenta no mesmo passo.", ["15", "14", "18", "13"], "Os passos são 3 por 3. Depois de 12, o próximo múltiplo de 3 é 15."],
    "TPR1_10": ["Complete a grade: 1, 3, 5/7, 9, 11/13, 15, ?", "Liste os números ímpares em ordem, linha por linha.", ["17", "16", "19", "18"], "A grade lista números ímpares consecutivos: 1, 3, 5, 7,…, 15, 17."],
    "TPR1_11": ["O que vem a seguir? ★, ★★, ★★★, ★★★★, ?", "Conte as estrelas em cada etapa.", ["★★★★★", "★★★★", "★★★", "★★★★★★"], "Uma estrela é adicionada a cada etapa: 1, 2, 3, 4, então seguem 5 estrelas."],
    "TPR1_12": ["O que vem a seguir? 6, 12, 18, 24, ?", "Cada termo é um múltiplo do mesmo número – qual?", ["30", "28", "36", "32"], "Os passos são de 6 a 6. Depois de 24, o próximo múltiplo de 6 é 30."],
    "TPR1_13": ["O que vem a seguir? M, N, O, P, ?", "São letras consecutivas do alfabeto.", ["P", "R", "N", "S"], "As letras continuam em ordem alfabética: M, N, O, P, Q."],
    "TPR1_14": ["O que vem a seguir? 1, 1, 1, 1, ?", "O valor muda alguma vez?", ["1", "2", "0", "3"], "Cada termo é 1 — o padrão é constante, então o próximo valor é 1."],
    "TPR1_15": ["O que vem a seguir? ♥, ♦, ♥, ♦, ♥, ?", "Dois símbolos se alternam.", ["♦", "♥", "♣", "♠"], "O padrão alterna coração e diamante. Depois do coração vem o diamante."],
    "TPR1_16": ["O que vem a seguir? 8, 16, 24, 32, ?", "Observe a diferença entre números consecutivos.", ["40", "36", "48", "38"], "Os passos vão de 8 a 8. Depois de 32, o próximo múltiplo de 8 é 40."],
    "TPR1_17": ["O que vem a seguir? ♠, ♠♠, ♠♠♠, ?", "Conte os símbolos do clube em cada etapa.", ["♠♠♠♠", "♠♠", "♠♠♠", "♠♠♠♠♠"], "Um trevo é adicionado a cada etapa: 1, 2, 3, então há 4 trevos."],
    "TPR1_18": ["O que vem a seguir? 30, 27, 24, 21, ?", "Os números diminuem em um passo fixo.", ["18", "20", "15", "19"], "Cada número diminui em 3. Depois de 21, o próximo valor é 18."],
    "TPR1_19": ["O que vem a seguir? 7, 14, 21, 28, ?", "Todo número é um múltiplo do mesmo número.", ["35", "36", "32", "42"], "Os passos são de 7 a 7. Depois de 28, o próximo múltiplo de 7 é 35."],
    "TPR1_20": ["Complete a grade: 2, 4, 6/8, 10, 12/14, 16, ?", "Liste os números pares linha por linha.", ["18", "20", "17", "19"], "A grade lista números pares consecutivos: 2, 4, 6, 8,…, 16, 18."],
    "TPR2_01": ["O que vem a seguir? X, XY, XYX, XYXY, ?", "A cada passo é adicionado mais um caractere, alternando entre X e Y.", ["XYXYX", "XYXYY", "YXYXY", "XYXY"], "O padrão cresce por adição alternada: o 5º termo possui 5 caracteres: XYXYX."],
    "TPR2_02": ["Grade: 3, 6, 9/5, 10, 15/8, 16, ?", "Veja como cada linha se relaciona com o primeiro número da linha.", ["24", "20", "18", "32"], "Cada linha multiplica o primeiro número por 1, 2, 3. Linha 3: 8×1=8, 8×2=16, 8×3=24."],
    "TPR2_03": ["O que vem a seguir? AA, BB, CC, DD, ?", "Cada par usa a próxima letra do alfabeto.", ["EE", "FF", "DE", "AB"], "Cada termo é uma letra consecutiva duplicada: A, B, C, D, E → EE."],
    "TPR2_04": ["O que vem a seguir? 1, 3, 5, 7, 9, ?", "São números ímpares.", ["11", "10", "13", "12"], "A string lista números ímpares consecutivos. Depois de 9, o próximo número ímpar é 11."],
    "TPR2_05": ["O que vem a seguir? ○●, ○●○, ○●○●, ○●○●○, ?", "A cada passo é adicionada mais uma forma, alternando ○ e ●.", ["○●○●○●", "○●○●○○", "●○●○●○", "○●○●●○"], "O padrão cresce em uma forma a cada etapa, alternando ○ e ●. O seguinte possui 6 formulários: ○●○●○●."],
    "TPR2_06": ["O que vem a seguir? 2, 6, 10, 14, ?", "Encontre a diferença constante entre os termos.", ["18", "16", "20", "15"], "Cada número aumenta em 4. Depois de 14, o próximo valor é 18."],
    "TPR2_07": ["O que vem a seguir? AB, CD, EF, GH, ?", "Cada par usa as próximas duas letras consecutivas.", ["EuJ", "JK", "OI", "KL"], "Os pares percorrem o alfabeto duas letras por vez: AB, CD, EF, GH, IJ."],
    "TPR2_08": ["Grade: 1, 3, 5/2, 4, 6/3, 5, ?", "Cada linha começa com um número maior e adiciona o mesmo passo.", ["7", "8", "6", "9"], "Cada linha lista três números que aumentam em 2. A linha 3 começa em 3: 3, 5, 7."],
    "TPR2_09": ["O que vem a seguir? ○, ■, ○, ■, ○, ■, ?", "Duas formas se repetem no ciclo.", ["○", "■", "△", "◇"], "O padrão alterna ○ e ■. Depois de ■ segue ○."],
    "TPR2_10": ["O que vem a seguir? 20, 17, 14, 11, ?", "Os números diminuem em um valor fixo.", ["8", "9", "7", "10"], "Cada número diminui em 3. Depois de 11, o próximo valor é 8."],
    "TPR2_11": ["O que vem a seguir? ABA, BCB, CDC, DED, ?", "Observe como as três letras de cada grupo se movem.", ["EFE", "FGF", "DEF", "EEE"], "Cada grupo segue o padrão: letra, próxima letra, mesma primeira letra – deslocada um passo em cada grupo. Depois do DED vem a EFE."],
    "TPR2_12": ["Grade: 5, 10, 15/6, 12, 18/7, 14, ?", "Cada linha multiplica o primeiro número por 1, 2 e 3.", ["21", "20", "24", "28"], "Linha 3: 7×1=7, 7×2=14, 7×3=21."],
    "TPR2_13": ["O que vem a seguir? 0, 2, 4, 6, 8, ?", "São números pares consecutivos começando em 0.", ["10", "12", "9", "11"], "A string lista números pares: 0, 2, 4, 6, 8, 10."],
    "TPR2_14": ["O que vem a seguir? ○○, ■■, ○○, ■■, ?", "Os pares de formas se alternam.", ["○○", "■■", "○■", "■○"], "O padrão alterna pares: ○○, ■■, ○○, ■■, ○○."],
    "TPR2_15": ["O que vem a seguir? 3, 7, 11, 15, 19, ?", "Encontre a diferença comum entre os termos.", ["23", "22", "21", "24"], "Cada número aumenta em 4. Depois de 19, o próximo valor é 23."],
    "TPR2_16": ["Grade: 1, 2, 3/2, 4, 6/3, 6, ?", "Compare cada linha com a linha acima dela.", ["9", "8", "10", "12"], "A linha n multiplica 1, 2, 3 por n. Linha 3: 3×1=3, 3×2=6, 3×3=9."],
    "TPR2_17": ["O que vem a seguir? XY, WX, VW, UV, ?", "Cada par move uma letra para trás no alfabeto.", ["VOCÊ", "ST", "RS", "SU"], "Cada par desce uma letra: XY → WX → VW → UV → TU."],
    "TPR2_18": ["O que vem a seguir? 40, 36, 32, 28, ?", "Os números diminuem por uma constante.", ["24", "25", "22", "20"], "Cada número diminui em 4. Depois de 28, o próximo valor é 24."],
    "TPR2_19": ["O que vem a seguir? ○, ○○, ■, ■■, ○, ?", "Uma única forma é seguida por seu duplo e depois pela próxima forma.", ["○○", "■", "○", "■■"], "O ciclo é: ○ simples, ○○ duplo, ■ simples, ■■ duplo e depois repetir. Depois de ○ vem ○○."],
    "TPR2_20": ["Grade: 10, 20, 30/11, 22, 33/12, 24, ?", "Cada linha multiplica o primeiro número por 1, 2 e 3.", ["36", "34", "38", "48"], "Linha 3: 12×1=12, 12×2=24, 12×3=36."],
    "TPR3_01": ["O que vem a seguir? 2, 3, 5, 8, 12, ?", "Observe as diferenças entre termos consecutivos — elas aumentam em 1.", ["17", "15", "16", "18"], "As diferenças são 1, 2, 3, 4, então a próxima diferença é 5: 12 + 5 = 17."],
    "TPR3_02": ["Grade: 3, 5, 15/4, 6, 24/7, 3, ?", "Como as duas primeiras colunas se relacionam com a terceira?", ["21", "10", "24", "30"], "Coluna 1 × coluna 2 = coluna 3. Linha 3: 7 × 3 = 21."],
    "TPR3_03": ["O que vem a seguir? 49, 36, 25, 16, 9, ?", "Cada termo é um quadrado perfeito – quais quadrados são eles?", ["4", "1", "6", "3"], "A string é 7², 6², 5², 4², 3², então 2² = 4 segue."],
    "TPR3_04": ["O que vem a seguir? 20, 18, 15, 11, 6, ?", "O valor baixo aumenta em 1 a cada etapa.", ["0", "1", "2", "−1"], "As diferenças são −2, −3, −4, −5, então o próximo é −6: 6 − 6 = 0."],
    "TPR3_05": ["Grade: 3, 9, 27/4, 16, 64/6, 36, ?", "Cada linha usa potências do primeiro número.", ["216", "180", "108", "72"], "O padrão de linha é n¹, n², n³. Linha 3: 6, 36, 216."],
    "TPR3_06": ["O que vem a seguir? 3, 5, 9, 15, 23, ?", "Calcule as diferenças – forme seu próprio padrão.", ["33", "31", "35", "29"], "As diferenças são 2, 4, 6, 8, então o próximo é 10: 23 + 10 = 33."],
    "TPR3_07": ["Grade: 1, 5, 6/2, 8, 10/3, 11, ?", "Adicione as duas primeiras colunas de cada linha.", ["14", "13", "15", "33"], "Coluna 1 + coluna 2 = coluna 3. Linha 3: 3 + 11 = 14."],
    "TPR3_08": ["O que vem a seguir? 1, 6, 15, 28, 45, ?", "Veja as diferenças e depois as diferenças dessas diferenças.", ["66", "60", "56", "72"], "As diferenças são 5, 9, 13, 17 (aumentar em 4). A próxima diferença é 21: 45 + 21 = 66."],
    "TPR3_09": ["O que vem a seguir? 100, 95, 85, 70, 50, ?", "Quanto diminui em cada etapa? Este montante está aumentando.", ["25", "30", "20", "35"], "As diferenças são −5, −10, −15, −20, então −25 segue: 50 − 25 = 25."],
    "TPR3_10": ["Grade: 3, 4, 12/5, 6, 30/7, 8, ?", "Como a coluna 3 se relaciona com as colunas 1 e 2?", ["56", "15", "48", "60"], "Coluna 1 × coluna 2 = coluna 3. Linha 3: 7 × 8 = 56."],
    "TPR3_11": ["O que vem a seguir? 3, 8, 15, 24, 35, ?", "Tente expressar cada termo como n² menos alguma coisa.", ["48", "44", "50", "42"], "Cada termo é n² − 1: 2²−1=3, 3²−1=8, 4²−1=15, 5²−1=24, 6²−1=35, 7²−1=48."],
    "TPR3_12": ["Grade: 2, 10, 5/3, 18, 6/4, 28, ?", "Como a coluna 3 se relaciona com as outras colunas?", ["7", "8", "12", "32"], "Coluna 2 ÷ coluna 1 = coluna 3. Linha 3: 28 ÷ 4 = 7."],
    "TPR3_13": ["O que vem a seguir? 5, 6, 8, 11, 15, 20, ?", "As diferenças entre os termos aumentam 1 em cada etapa.", ["26", "25", "27", "24"], "As diferenças são 1, 2, 3, 4, 5, então o próximo é 6: 20 + 6 = 26."],
    "TPR3_14": ["O que vem a seguir? 2, 5, 10, 17, 26, ?", "Experimente a fórmula n² + 1 para valores consecutivos de n.", ["37", "35", "38", "36"], "Cada termo é n² + 1: 1²+1=2, 2²+1=5, 3²+1=10, 4²+1=17, 5²+1=26, 6²+1=37."],
    "TPR3_15": ["Grade: 2, 5, 7/3, 4, 7/8, 3, ?", "Adicione as duas primeiras colunas de cada linha.", ["11", "24", "5", "10"], "Coluna 1 + coluna 2 = coluna 3. Linha 3: 8 + 3 = 11."],
    "TPR3_16": ["Grade: 6, 2, 3/15, 3, 5/24, 4, ?", "Divida a coluna 1 pela coluna 2.", ["6", "8", "7", "28"], "Coluna 1 ÷ coluna 2 = coluna 3. Linha 3: 24 ÷ 4 = 6."],
    "TPR3_17": ["O que vem a seguir? 2, 8, 32, 128, ?", "Cada termo é multiplicado pelo mesmo número.", ["512", "256", "384", "640"], "Cada termo é multiplicado por 4. Depois de 128, o próximo termo é 128 × 4 = 512."],
    "TPR3_18": ["O que vem a seguir? 10, 12, 16, 22, 30, ?", "Veja como o intervalo entre os termos muda.", ["40", "38", "42", "36"], "As diferenças são 2, 4, 6, 8, então o próximo é 10: 30 + 10 = 40."],
    "TPR3_19": ["O que vem a seguir? 4, 7, 12, 19, 28, ?", "As diferenças entre os termos aumentam em 2 em cada etapa.", ["39", "37", "41", "35"], "As diferenças são 3, 5, 7, 9, então o próximo é 11: 28 + 11 = 39."],
    "TPR3_20": ["Grade: 4, 2, 8/9, 3, 27/16, 4, ?", "A coluna 1 é um quadrado perfeito. Quais são os valores do cubo?", ["64", "48", "32", "20"], "Coluna 1 = n², coluna 2 = n, coluna 3 = n³. Linha 3: 4² = 16, 4, 4³ = 64."],
    "TPR4_01": ["O que vem a seguir? 1, 16, 81, 256, ?", "Cada termo é uma quarta potência.", ["625", "512", "500", "1024"], "A string é 1⁴, 2⁴, 3⁴, 4⁴, então 5⁴ = 625 segue."],
    "TPR4_02": ["Grade: 5, 25, 125/6, 36, 216/7, 49, ?", "Cada linha mostra n, n², n³.", ["343", "294", "350", "336"], "Linha 3: 7¹ = 7, 7² = 49, 7³ = 343."],
    "TPR4_03": ["O que vem a seguir? 2, 8, 26, 80, 242, ?", "Tente expressar cada termo como uma potência de 3 menos 1.", ["728", "486", "720", "500"], "Cada termo é 3ⁿ − 1: 3¹−1=2, 3²−1=8, 3³−1=26, 3⁴−1=80, 3⁵−1=242, 3⁶−1=728."],
    "TPR4_04": ["O que vem a seguir? 1, 4, 13, 40, 121, ?", "Cada termo triplica e depois aumenta em 1.", ["364", "242", "360", "400"], "Cada termo = anterior × 3 + 1: 1→4, 4→13, 13→40, 40→121, 121→364."],
    "TPR4_05": ["O que vem a seguir? 2, 3, 5, 8, 13, ?", "Observe as diferenças – segue um padrão familiar.", ["21", "18", "20", "16"], "As diferenças são 1, 2, 3, 5, 8 – cada diferença é a soma das duas anteriores. A próxima diferença é 8, então 13 + 8 = 21."],
    "TPR4_06": ["O que vem a seguir? 1, 4, 10, 20, 35, ?", "Observe as diferenças de segunda ordem – elas aumentam em 1.", ["56", "50", "48", "55"], "Diferenças de primeira ordem: 3, 6, 10, 15. Diferenças de segunda ordem: 3, 4, 5 → próximo 6. Próxima diferença de primeira ordem: 21. Resposta: 35 + 21 = 56."],
    "TPR4_07": ["O que vem a seguir? 1, 3, 2, 6, 4, 12, 8, ?", "Divide a string em termos em posições ímpares e em posições pares.", ["24", "16", "10", "20"], "Posições ímpares: 1, 2, 4, 8 (×2). Posições pares: 3, 6, 12, 24 (×2). O próximo termo par é 24."],
    "TPR4_08": ["Grade: 2, 3, 11/4, 5, 29/6, 7, ?", "Experimente (coluna1 + 1) × (coluna2 + 1) e ajuste.", ["55", "42", "48", "53"], "Coluna 3 = (coluna 1 + 1) × (coluna 2 + 1) − 1. Linha 3: 7 × 8 − 1 = 55."],
    "TPR4_09": ["O que vem a seguir? 256, 128, 64, 32, 16, ?", "Cada termo é dividido pela metade.", ["8", "4", "12", "10"], "Cada termo é divisível por 2. Depois de 16, o próximo termo é 16 ÷ 2 = 8."],
    "TPR4_10": ["Grade: 1, 2, 3, 6/2, 3, 5, 30/3, 4, 7, ?", "Como a última coluna se relaciona com as três primeiras?", ["84", "14", "21", "72"], "Coluna 4 = coluna 1 × coluna 2 × coluna 3. Linha 3: 3 × 4 × 7 = 84."],
    "TPR4_11": ["O que vem a seguir? 2, 6, 18, 54, ?", "Cada termo é multiplicado pelo mesmo número.", ["162", "108", "144", "216"], "Cada termo é multiplicado por 3. Depois de 54, o próximo termo é 54 × 3 = 162."],
    "TPR4_12": ["O que vem a seguir? 1, 5, 14, 30, 55, ?", "As diferenças entre os termos são quadrados perfeitos.", ["91", "80", "85", "90"], "As diferenças são 4, 9, 16, 25 (ou seja, 2², 3², 4², 5²). A próxima diferença é 6² = 36: 55 + 36 = 91."],
    "TPR4_13": ["O que vem a seguir? 1000, 500, 250, 125, ?", "Cada termo é dividido pela metade.", ["62,5", "60", "75", "100"], "Cada termo é divisível por 2. Depois de 125, o próximo termo é 125 ÷ 2 = 62,5."],
    "TPR4_14": ["Grade: 10, 3, 7/20, 8, 12/30, 11, ?", "Como as colunas estão relacionadas aritmeticamente?", ["19", "20", "21", "41"], "Coluna 1 - coluna 2 = coluna 3. Linha 3: 30 - 11 = 19."],
    "TPR4_15": ["O que vem a seguir? 4, 5, 9, 14, 23, 37, ?", "Cada termo é a soma dos dois termos anteriores.", ["60", "51", "56", "74"], "Tal como acontece com Fibonacci: cada termo = a soma dos dois anteriores. 23 + 37 = 60."],
    "TPR4_16": ["Grade: 2, 8, 3/3, 27, 8/4, 64, ?", "A coluna 2 é uma potência da coluna 1. Que padrão segue a coluna 3?", ["15", "16", "12", "20"], "Coluna 2 = coluna 1³. Coluna 3 = coluna 1² − 1: 2²−1=3, 3²−1=8, 4²−1=15."],
    "TPR4_17": ["O que vem a seguir? 1, 5, 21, 85, ?", "Tente multiplicar cada termo por 4 e adicionar 1.", ["341", "256", "340", "345"], "Cada termo = anterior × 4 + 1: 1→5, 5→21, 21→85, 85→341."],
    "TPR4_18": ["O que vem a seguir? 1, 2, 5, 12, 29, ?", "Cada termo usa os dois anteriores com um multiplicador.", ["70", "58", "65", "72"], "Regra: a(n) = 2×a(n−1) + a(n−2). Verifique: 2×2+1=5, 2×5+2=12, 2×12+5=29, 2×29+12=70."],
    "TPR4_19": ["Grade: 3, 2, 11/4, 3, 19/5, 4, ?", "Tente elevar ao quadrado a coluna 1 mais a coluna 2.", ["29", "20", "25", "30"], "Coluna 3 = coluna 1² + coluna 2. Linha 3: 5² + 4 = 25 + 4 = 29."],
    "TPR4_20": ["Grade: 4, 3, 13/5, 2, 23/6, 1, ?", "Experimente a coluna 1 ao quadrado menos a coluna 2.", ["35", "30", "36", "42"], "Coluna 3 = coluna 1² − coluna 2. Linha 3: 6² − 1 = 36 − 1 = 35."],
    "TPR5_01": ["O que vem a seguir na sequência de números primos? 23, 29, 31, 37, 41, ?", "Liste os números primos depois de 41.", ["43", "42", "45", "47"], "String lista números primos consecutivos. Depois de 41, o próximo número primo é 43."],
    "TPR5_02": ["O que vem a seguir? 2, 1, 3, 4, 7, 11, 18, ?", "Cada termo é a soma dos dois termos anteriores.", ["29", "25", "27", "36"], "Série de Lucas: cada termo = a soma dos dois anteriores. 11 + 18 = 29."],
    "TPR5_03": ["Grade: 2, 8, 32/3, 27, 243/5, 125, ?", "Cada coluna usa uma potência ímpar do primeiro número.", ["3125", "625", "1250", "1500"], "O padrão de linha é n¹, n³, n⁵. Linha 3: 5¹=5, 5³=125, 5⁵=3125."],
    "TPR5_04": ["O que vem a seguir? 4, 6, 10, 14, 22, 26, ?", "Cada termo é duas vezes um número primo. Quais prêmios?", ["34", "30", "32", "38"], "Cada termo é 2 × um número primo consecutivo: 2×2=4, 2×3=6, 2×5=10, 2×7=14, 2×11=22, 2×13=26, 2×17=34."],
    "TPR5_05": ["O que vem a seguir? 0, 0, 1, 1, 2, 4, 7, 13, ?", "Cada termo é a soma dos três termos anteriores.", ["24", "20", "26", "19"], "É a série de Tribonacci: cada termo = a soma dos três anteriores. 4 + 7 + 13 = 24."],
    "TPR5_06": ["O que vem a seguir? 2, 12, 36, 80, 150, ?", "Tente expressar cada termo como n²(n + 1).", ["252", "210", "240", "260"], "Cada termo é n²(n+1): 1²×2=2, 2²×3=12, 3²×4=36, 4²×5=80, 5²×6=150, 6²×7=252."],
    "TPR5_07": ["Grade: 1, 2, 5/2, 3, 13/4, 5, ?", "Experimente os quadrados das duas primeiras colunas adicionadas.", ["41", "20", "45", "36"], "Coluna 3 = coluna 1² + coluna 2². Linha 3: 4² + 5² = 16 + 25 = 41."],
    "TPR5_08": ["O que vem a seguir? 2, 8, 18, 32, 50, ?", "Tente expressar cada termo como 2n² para n consecutivos.", ["72", "60", "68", "80"], "Cada termo é 2n²: 2(1²)=2, 2(2²)=8, 2(3²)=18, 2(4²)=32, 2(5²)=50, 2(6²)=72."],
    "TPR5_09": ["O que vem a seguir? 2, 4, 16, 256, ?", "Cada termo é o quadrado do termo anterior.", ["65536", "512", "1024", "4096"], "Cada termo = anterior². 2²=4, 4²=16, 16²=256, 256²=65536."],
    "TPR5_10": ["O que vem a seguir? 47, 43, 41, 37, 31, 29, ?", "Eles são números primos em ordem decrescente.", ["23", "27", "25", "19"], "String lista números primos consecutivos em ordem decrescente. Depois de 29, o próximo menor número primo é 23."],
    "TPR5_11": ["Grade: 2, 3, 7/4, 5, 21/6, 7, ?", "Multiplique as duas primeiras colunas e ajuste por 1.", ["43", "42", "44", "40"], "Coluna 3 = coluna 1 × coluna 2 + 1. Linha 3: 6 × 7 + 1 = 43."],
    "TPR5_12": ["O que vem a seguir? 1, 5, 12, 22, 35, ?", "Estes são números pentagonais: n(3n − 1)/2.", ["51", "48", "50", "55"], "Números pentagonais: n(3n−1)/2. Para n=6: 6×17/2 = 51."],
    "TPR5_13": ["O que vem a seguir? 2, 6, 30, 210, ?", "Cada termo é multiplicado pelo próximo número primo.", ["2310", "1470", "1260", "1890"], "2×3=6, 6×5=30, 30×7=210, 210×11=2310. A cada passo você multiplica pelo próximo número primo."],
    "TPR5_14": ["Grade: 4, 16, 64/6, 36, 216/8, 64, ?", "Cada linha mostra potências do primeiro número.", ["512", "256", "480", "128"], "O padrão de linha é n¹, n², n³. Linha 3: 8, 64, 512."],
    "TPR5_15": ["O que vem a seguir? 1, 3, 11, 43, ?", "Cada termo é multiplicado por 4 e diminuído por 1.", ["171", "170", "172", "160"], "Cada termo = anterior × 4 − 1: 1→3, 3→11, 11→43, 43→171."],
    "TPR5_16": ["O que vem a seguir? 59, 53, 47, 43, 41, 37, ?", "Esses são números primos em ordem decrescente.", ["31", "33", "29", "35"], "String lista números primos consecutivos em ordem inversa. Depois de 37, o próximo menor número primo é 31."],
    "TPR5_17": ["O que vem a seguir? 27, 125, 343, 729, ?", "Cada termo é um cubo – de quem são os números?", ["1331", "1000", "1200", "1500"], "Estes são cubos de números ímpares consecutivos: 3³=27, 5³=125, 7³=343, 9³=729, 11³=1331."],
    "TPR5_18": ["Grade: 3, 2, 18/4, 3, 48/5, 4, ?", "Tente elevar ao quadrado a coluna1 multiplicada pela coluna2.", ["100", "80", "60", "125"], "Coluna 3 = coluna 1² × coluna 2. Linha 3: 5² × 4 = 25 × 4 = 100."],
    "TPR5_19": ["O que vem a seguir? 2, 3, 6, 7, 14, 15, ?", "A string alterna entre duas operações.", ["30", "16", "28", "22"], "O padrão alterna +1 e ×2: 2+1=3, 3×2=6, 6+1=7, 7×2=14, 14+1=15, 15×2=30."],
    "TPR5_20": ["O que vem a seguir? 1, 9, 36, 100, 225, ?", "Cada termo é um quadrado perfeito. Para quais números eles são elevados?", ["441", "400", "484", "500"], "Estes são quadrados de somas cumulativas: (1)²=1, (1+2)²=9, (1+2+3)²=36, (1+2+3+4)²=100, (1+2+3+4+5)²=225, (1+2+3+4+5+6)²=441."],
    "TNR1_01": ["O que vem a seguir na string: 7, 8, 9, 10, 11, ?", "Observe a diferença entre cada par de termos consecutivos.", ["12", "13", "10", "14"], "Cada termo aumenta em 1. O próximo termo é 11 + 1 = 12."],
    "TNR1_02": ["O que vem a seguir na string: 3, 5, 7, 9, 11, ?", "Subtraia cada termo do próximo.", ["13", "12", "14", "15"], "Cada termo aumenta em 2. O próximo termo é 11 + 2 = 13."],
    "TNR1_03": ["O que vem a seguir na string: 10, 13, 16, 19, 22, ?", "Encontra a diferença constante entre termos consecutivos.", ["25", "24", "26", "23"], "Cada termo aumenta em 3. O próximo termo é 22 + 3 = 25."],
    "TNR1_04": ["O que vem a seguir na string: 1, 5, 9, 13, 17, ?", "Quanto cada termo aumenta em relação ao anterior?", ["21", "20", "22", "19"], "Cada termo aumenta em 4. O próximo termo é 17 + 4 = 21."],
    "TNR1_05": ["O que vem a seguir na string: 2, 7, 12, 17, 22, ?", "Calcula o passo entre termos consecutivos.", ["27", "25", "28", "26"], "Cada termo aumenta em 5. O próximo termo é 22 + 5 = 27."],
    "TNR1_06": ["O que vem a seguir na string: 4, 10, 16, 22, 28, ?", "O que é adicionado a cada vez?", ["34", "32", "36", "30"], "Cada termo aumenta em 6. O próximo termo é 28 + 6 = 34."],
    "TNR1_07": ["O que vem a seguir na string: 3, 10, 17, 24, 31, ?", "Encontre a constante adicionada a cada termo.", ["38", "35", "39", "37"], "Cada termo aumenta em 7. O próximo termo é 31 + 7 = 38."],
    "TNR1_08": ["O que vem a seguir na string: 5, 13, 21, 29, 37, ?", "Subtraia o primeiro termo do segundo para encontrar o tamanho do passo.", ["45", "44", "46", "43"], "Cada termo aumenta em 8. O próximo termo é 37 + 8 = 45."],
    "TNR1_09": ["O que vem a seguir na string: 2, 11, 20, 29, 38, ?", "Que número é adicionado a cada etapa?", ["47", "45", "48", "46"], "Cada termo aumenta em 9. O próximo termo é 38 + 9 = 47."],
    "TNR1_10": ["O que vem a seguir na string: 6, 16, 26, 36, 46, ?", "Observe o intervalo entre quaisquer dois termos consecutivos.", ["56", "54", "58", "52"], "Cada termo aumenta em 10. O próximo termo é 46 + 10 = 56."],
    "TNR1_11": ["O que vem a seguir na string: 20, 19, 18, 17, 16, ?", "A corda diminui. Quanto em cada etapa?", ["15", "14", "17", "13"], "Cada termo diminui em 1. O próximo termo é 16 − 1 = 15."],
    "TNR1_12": ["O que vem a seguir na string: 30, 28, 26, 24, 22, ?", "Subtraia cada termo do anterior.", ["20", "21", "18", "19"], "Cada termo diminui em 2. O próximo termo é 22 − 2 = 20."],
    "TNR1_13": ["O que vem a seguir na string: 40, 37, 34, 31, 28, ?", "A corda diminui. Encontre seu ritmo constante.", ["25", "26", "24", "27"], "Cada termo diminui em 3. O próximo termo é 28 − 3 = 25."],
    "TNR1_14": ["O que vem a seguir na string: 50, 46, 42, 38, 34, ?", "Quanto diminui a cada vez?", ["30", "32", "28", "31"], "Cada termo diminui em 4. O próximo termo é 34 − 4 = 30."],
    "TNR1_15": ["O que vem a seguir na string: 60, 55, 50, 45, 40, ?", "Encontra a medida mais baixa entre termos consecutivos.", ["35", "30", "38", "33"], "Cada termo diminui em 5. O próximo termo é 40 − 5 = 35."],
    "TNR1_16": ["O que vem a seguir na string: 5, 16, 27, 38, 49, ?", "Calcule a diferença entre os dois primeiros termos e verifique se permanece igual.", ["60", "58", "61", "55"], "Cada termo aumenta em 11. O próximo termo é 49 + 11 = 60."],
    "TNR1_17": ["O que vem a seguir na string: 3, 15, 27, 39, 51, ?", "Qual é a constante adicionada em cada etapa?", ["63", "60", "64", "62"], "Cada termo aumenta em 12. O próximo termo é 51 + 12 = 63."],
    "TNR1_18": ["O que vem a seguir na string: 10, 25, 40, 55, 70, ?", "Encontra o tom fixo adicionado entre os termos.", ["85", "80", "90", "75"], "Cada termo aumenta em 15. O próximo termo é 70 + 15 = 85."],
    "TNR1_19": ["O que vem a seguir na string: 5, 25, 45, 65, 85, ?", "Calcula o tamanho do passo de qualquer termo para o próximo.", ["105", "100", "110", "95"], "Cada termo aumenta em 20. O próximo termo é 85 + 20 = 105."],
    "TNR1_20": ["O que vem a seguir na string: 42, 36, 30, 24, 18, ?", "A corda diminui. O que é subtraído de cada vez?", ["12", "14", "10", "16"], "Cada termo diminui em 6. O próximo termo é 18 − 6 = 12."],
    "TNR2_01": ["O que vem a seguir na string: 5, 10, 20, 40, 80, ?", "Tente dividir cada termo pelo anterior.", ["160", "120", "140", "100"], "Cada termo é multiplicado por 2. O próximo termo é 80 × 2 = 160."],
    "TNR2_02": ["O que vem a seguir na string: 2, 6, 18, 54, 162, ?", "Qual é a proporção de termos consecutivos?", ["486", "324", "480", "648"], "Cada termo é multiplicado por 3. O próximo termo é 162 × 3 = 486."],
    "TNR2_03": ["O que vem a seguir na string: 1, 4, 16, 64, 256, ?", "Divida o segundo termo pelo primeiro para encontrar o multiplicador.", ["1024", "512", "768", "1280"], "Cada termo é multiplicado por 4. O próximo termo é 256 × 4 = 1024."],
    "TNR2_04": ["O que vem a seguir na string: 2, 10, 50, 250, 1250, ?", "Observe a proporção de termos consecutivos.", ["6250", "5.000", "6.000", "7500"], "Cada termo é multiplicado por 5. O próximo termo é 1250 × 5 = 6250."],
    "TNR2_05": ["O que vem a seguir na string: 3, 30, 300, 3000, 30000, ?", "Cada termo recebe outro zero. Pelo que isso se multiplica?", ["300.000", "60.000", "200.000", "330.000"], "Cada termo é multiplicado por 10. O próximo termo é 30.000 × 10 = 300.000."],
    "TNR2_06": ["O que vem a seguir na string: 640, 320, 160, 80, 40, ?", "A string é dividida pela metade. Qual operação é aplicada em cada etapa?", ["20", "10", "30", "25"], "Cada termo é divisível por 2. O próximo termo é 40 ÷ 2 = 20."],
    "TNR2_07": ["O que vem a seguir na string: 729, 243, 81, 27, 9, ?", "Tente dividir cada termo no próximo.", ["3", "6", "1", "4"], "Cada termo é divisível por 3. O próximo termo é 9 ÷ 3 = 3."],
    "TNR2_08": ["O que vem a seguir na string: 192, 96, 48, 24, 12, ?", "Que fração do termo anterior dá o termo atual?", ["6", "4", "8", "3"], "Cada termo é divisível por 2. O próximo termo é 12 ÷ 2 = 6."],
    "TNR2_09": ["O que vem a seguir na string: 3, 4, 7, 11, 18, ?", "Tente adicionar dois termos consecutivos.", ["29", "25", "27", "30"], "Cada termo é a soma dos dois anteriores: 11 + 18 = 29."],
    "TNR2_10": ["O que vem a seguir na string: 2, 5, 7, 12, 19, ?", "Veja como cada termo se relaciona com os dois anteriores.", ["31", "26", "28", "33"], "Cada termo é a soma dos dois anteriores: 12 + 19 = 31."],
    "TNR2_11": ["O que vem a seguir na string: 4, 9, 19, 39, 79, ?", "Tente duplicar um termo e depois ajustar por um pequeno número.", ["159", "158", "160", "149"], "Cada termo segue a regra: anterior × 2 + 1. O próximo termo é 79 × 2 + 1 = 159."],
    "TNR2_12": ["O que vem a seguir na string: 4, 12, 36, 108, 324, ?", "Divida cada termo pelo termo anterior para encontrar uma razão constante.", ["972", "648", "1296", "900"], "Cada termo é multiplicado por 3. O próximo termo é 324 × 3 = 972."],
    "TNR2_13": ["O que vem a seguir na string: 7, 14, 28, 56, 112, ?", "O que acontece quando você divide cada termo pelo termo anterior?", ["224", "168", "220", "228"], "Cada termo é multiplicado por 2. O próximo termo é 112 × 2 = 224."],
    "TNR2_14": ["O que vem a seguir na string: 1, 3, 4, 7, 11, ?", "Verifique se cada termo é a soma dos dois anteriores.", ["18", "15", "16", "20"], "Cada termo é a soma dos dois anteriores: 7 + 11 = 18."],
    "TNR2_15": ["O que vem a seguir na string: 256, 128, 64, 32, 16, ?", "Todas essas são potências de 2. Qual divisor conecta cada par?", ["8", "4", "12", "10"], "Cada termo é divisível por 2. O próximo termo é 16 ÷ 2 = 8."],
    "TNR2_16": ["O que vem a seguir na string: 1, 5, 25, 125, 625, ?", "Encontre o multiplicador dividindo qualquer termo pelo termo anterior.", ["3125", "1250", "3.000", "3750"], "Cada termo é multiplicado por 5. O próximo termo é 625 × 5 = 3125."],
    "TNR2_17": ["O que vem a seguir na string: 3, 8, 18, 38, 78, ?", "Tente duplicar o termo anterior e adicionar uma pequena constante.", ["158", "156", "160", "148"], "Cada termo segue a regra: anterior × 2 + 2. O próximo termo é 78 × 2 + 2 = 158."],
    "TNR2_18": ["O que vem a seguir na string: 1, 4, 5, 9, 14, ?", "Veja se a soma de dois termos consecutivos dá o seguinte.", ["23", "19", "21", "25"], "Cada termo é a soma dos dois anteriores: 9 + 14 = 23."],
    "TNR2_19": ["O que vem a seguir na string: 2187, 729, 243, 81, 27, ?", "Cada termo é uma fração do anterior. Qual divisor é usado?", ["9", "3", "18", "12"], "Cada termo é divisível por 3. O próximo termo é 27 ÷ 3 = 9."],
    "TNR2_20": ["O que vem a seguir na string: 2, 8, 32, 128, 512, ?", "Divida os termos consecutivos para encontrar o multiplicador constante.", ["2048", "1024", "2560", "1536"], "Cada termo é multiplicado por 4. O próximo termo é 512 × 4 = 2.048."],
    "TNR3_01": ["O que vem a seguir na string: 36, 49, 64, 81, 100, ?", "Experimente a raiz quadrada de cada termo.", ["121", "110", "120", "125"], "São quadrados perfeitos consecutivos: 6²=36, 7²=49, 8²=64, 9²=81, 10²=100, 11²=121."],
    "TNR3_02": ["O que vem a seguir na string: 100, 121, 144, 169, 196, ?", "Cada termo é um quadrado perfeito. Que quadrados são esses?", ["225", "220", "230", "216"], "São quadrados perfeitos consecutivos: 10²=100, 11²=121, 12²=144, 13²=169, 14²=196, 15²=225."],
    "TNR3_03": ["O que vem a seguir na string: 125, 216, 343, 512, 729, ?", "Experimente a raiz cúbica de cada termo.", ["1000", "900", "1024", "972"], "São cubos perfeitos consecutivos: 5³=125, 6³=216, 7³=343, 8³=512, 9³=729, 10³=1000."],
    "TNR3_04": ["O que vem a seguir na string: 343, 512, 729, 1000, 1331, ?", "Estes são cubos de inteiros consecutivos. Quais inteiros?", ["1728", "1500", "1700", "2000"], "São cubos perfeitos consecutivos: 7³=343, 8³=512, 9³=729, 10³=1000, 11³=1331, 12³=1728."],
    "TNR3_05": ["O que vem a seguir na string: 10, 12, 16, 22, 30, ?", "Calcule as diferenças entre os termos. Essas diferenças formam um padrão?", ["40", "38", "42", "36"], "As diferenças são 2, 4, 6, 8 — aumentando em 2 a cada passo. A próxima diferença é 10, então 30 + 10 = 40."],
    "TNR3_06": ["O que vem a seguir na string: 7, 10, 16, 25, 37, ?", "Encontre as diferenças entre os termos e procure um padrão nessas diferenças.", ["52", "49", "55", "46"], "As diferenças são 3, 6, 9, 12 — aumentando em 3 a cada passo. A próxima diferença é 15, então 37 + 15 = 52."],
    "TNR3_07": ["O que vem a seguir na string: 5, 6, 9, 14, 21, ?", "As diferenças entre os termos são números ímpares consecutivos.", ["30", "28", "32", "27"], "As diferenças são 1, 3, 5, 7 — números ímpares consecutivos. A próxima diferença é 9, então 21 + 9 = 30."],
    "TNR3_08": ["O que vem a seguir na string: 5, 7, 11, 13, 17, ?", "Pense em números que possuem exatamente dois divisores.", ["19", "18", "21", "20"], "São números primos consecutivos começando em 5. O próximo número primo depois de 17 é 19."],
    "TNR3_09": ["O que vem a seguir na string: 11, 13, 17, 19, 23, ?", "Esses números são divisíveis apenas por 1 e por eles mesmos?", ["29", "27", "25", "31"], "São números primos consecutivos começando em 11. O próximo número primo depois de 23 é 29."],
    "TNR3_10": ["O que vem a seguir na string: 4, 16, 36, 64, 100, ?", "Extraia a raiz quadrada de cada termo. O que esses números têm em comum?", ["144", "128", "136", "148"], "Estes são quadrados de números pares consecutivos: 2²=4, 4²=16, 6²=36, 8²=64, 10²=100, 12²=144."],
    "TNR3_11": ["O que vem a seguir na string: 1, 9, 25, 49, 81, ?", "Extraia a raiz quadrada de cada termo. Que tipo de números são eles?", ["121", "100", "110", "125"], "São quadrados de números ímpares consecutivos: 1²=1, 3²=9, 5²=25, 7²=49, 9²=81, 11²=121."],
    "TNR3_12": ["O que vem a seguir na string: 2, 5, 10, 17, 26, ?", "Subtraia 1 de cada termo. Os resultados parecem familiares?", ["37", "35", "36", "39"], "Cada termo é n² + 1: 1²+1=2, 2²+1=5, 3²+1=10, 4²+1=17, 5²+1=26, 6²+1=37."],
    "TNR3_13": ["O que vem a seguir na string: 0, 3, 8, 15, 24, ?", "Adicione 1 a cada termo. Que string conhecida você consegue?", ["35", "33", "36", "30"], "Cada termo é n² − 1: 1²−1=0, 2²−1=3, 3²−1=8, 4²−1=15, 5²−1=24, 6²−1=35."],
    "TNR3_14": ["O que vem a seguir na string: 5, 9, 17, 29, 45, ?", "Calcule as diferenças e verifique se elas aumentam regularmente.", ["65", "61", "69", "57"], "As diferenças são 4, 8, 12, 16 — aumentando em 4 a cada passo. A próxima diferença é 20, então 45 + 20 = 65."],
    "TNR3_15": ["O que vem a seguir na string: 2, 9, 28, 65, 126, ?", "Subtraia 1 de cada termo. Que tipo de números sobraram?", ["217", "215", "220", "210"], "Cada termo é n³ + 1: 1³+1=2, 2³+1=9, 3³+1=28, 4³+1=65, 5³+1=126, 6³+1=217."],
    "TNR3_16": ["O que vem a seguir na string: 3, 8, 15, 24, 35, ?", "Tente expressar cada termo como um produto de dois números adjacentes.", ["48", "46", "50", "44"], "Cada termo é n(n + 2): 1×3=3, 2×4=8, 3×5=15, 4×6=24, 5×7=35, 6×8=48."],
    "TNR3_17": ["O que vem a seguir na string: 1, 5, 11, 19, 29, ?", "As diferenças entre os termos aumentam com uma constante. Encontre essa constante.", ["41", "39", "43", "37"], "As diferenças são 4, 6, 8, 10 — aumentando em 2 a cada passo. A próxima diferença é 12, então 29 + 12 = 41."],
    "TNR3_18": ["O que vem a seguir na string: 2, 8, 18, 32, 50, ?", "Experimente dividir cada termo por 2. Os resultados parecem familiares?", ["72", "68", "74", "64"], "Cada termo é 2n²: 2(1²)=2, 2(2²)=8, 2(3²)=18, 2(4²)=32, 2(5²)=50, 2(6²)=72."],
    "TNR3_19": ["O que vem a seguir na string: 4, 7, 12, 19, 28, ?", "Subtraia 3 de cada termo. Que string você reconhece?", ["39", "37", "41", "36"], "Cada termo é n² + 3: 1²+3=4, 2²+3=7, 3²+3=12, 4²+3=19, 5²+3=28, 6²+3=39."],
    "TNR3_20": ["O que vem a seguir na string: 4, 9, 19, 34, 54, ?", "Encontre as diferenças e depois as diferenças dessas diferenças.", ["79", "74", "84", "69"], "As diferenças são 5, 10, 15, 20 — aumentando em 5 a cada passo. A próxima diferença é 25, então 54 + 25 = 79."],
    "TNR4_01": ["O que vem a seguir na string: 2, 3, 7, 25, 121, ?", "Subtraia 1 de cada termo e veja se você reconhece os números.", ["721", "720", "625", "719"], "Cada termo é n! + 1: 1!+1=2, 2!+1=3, 3!+1=7, 4!+1=25, 5!+1=121, 6!+1=721."],
    "TNR4_02": ["O que vem a seguir na string: 0, 1, 5, 23, 119, ?", "Adicione 1 a cada termo. Você reconhece os números resultantes?", ["719", "720", "600", "721"], "Cada termo é n! − 1: 1!−1=0, 2!−1=1, 3!−1=5, 4!−1=23, 5!−1=119, 6!−1=719."],
    "TNR4_03": ["O que vem a seguir na string: 15, 21, 28, 36, 45, ?", "Estes são números triangulares. As diferenças entre os termos aumentam 1 em cada etapa.", ["55", "54", "56", "50"], "Números triangulares T(5)–T(10). As diferenças são 6, 7, 8, 9, então o próximo é 10: 45 + 10 = 55."],
    "TNR4_04": ["O que vem a seguir na string: 36, 45, 55, 66, 78, ?", "Calcule as diferenças. Eles aumentam 1 a cada vez – sinal dos números triangulares.", ["91", "88", "90", "84"], "Números triangulares T(8)–T(13). As diferenças são 9, 10, 11, 12, então o próximo é 13: 78 + 13 = 91."],
    "TNR4_05": ["O que vem a seguir na string: 1, 5, 13, 29, 61, ?", "Tente duplicar o termo anterior e adicionar uma pequena constante.", ["125", "122", "123", "127"], "Cada termo segue a regra: anterior × 2 + 3. O próximo termo é 61 × 2 + 3 = 125."],
    "TNR4_06": ["O que vem a seguir na string: 1, 2, 5, 14, 41, ?", "Tente multiplicar o termo anterior por 3 e ajuste.", ["122", "120", "123", "82"], "Cada termo segue a regra: anterior × 3 − 1. O próximo termo é 41 × 3 − 1 = 122."],
    "TNR4_07": ["O que vem a seguir na string: 2, 9, 23, 51, 107, ?", "Dobre o termo anterior e adicione uma constante para obter o próximo.", ["219", "214", "215", "221"], "Cada termo segue a regra: anterior × 2 + 5. O próximo termo é 107 × 2 + 5 = 219."],
    "TNR4_08": ["O que vem a seguir na string: 9, 25, 49, 121, 169, ?", "Tire a raiz quadrada de cada termo e pense no que há de especial nesses números.", ["289", "225", "256", "324"], "Estes são quadrados de números primos consecutivos: 3²=9, 5²=25, 7²=49, 11²=121, 13²=169, 17²=289."],
    "TNR4_09": ["O que vem a seguir na string: 10, 11, 15, 24, 40, ?", "Encontre as diferenças entre os termos. Essas diferenças são uma string conhecida?", ["65", "56", "64", "60"], "As diferenças são 1, 4, 9, 16 — quadrados perfeitos (1², 2², 3², 4²). A próxima diferença é 5²=25, então 40 + 25 = 65."],
    "TNR4_10": ["O que vem a seguir na string: 0, 1, 3, 9, 33, ?", "Calcule as diferenças entre os termos. Eles lembram você de uma frase famosa?", ["153", "129", "150", "57"], "As diferenças são 1, 2, 6, 24 — isto é, fatorial (1!, 2!, 3!, 4!). A próxima diferença é 5!=120, então 33 + 120 = 153."],
    "TNR4_11": ["O que vem a seguir na string: 2, 7, 22, 67, 202, ?", "Multiplique o termo anterior por um número e adicione uma constante.", ["607", "606", "605", "610"], "Cada termo segue a regra: anterior × 3 + 1. O próximo termo é 202 × 3 + 1 = 607."],
    "TNR4_12": ["O que vem a seguir na string: 20, 37, 71, 139, 275, ?", "Tente duplicar o termo anterior e subtrair uma pequena constante.", ["547", "550", "545", "553"], "Cada termo segue a regra: anterior × 2 − 3. O próximo termo é 275 × 2 − 3 = 547."],
    "TNR4_13": ["O que vem a seguir na string: 1, 5, 14, 30, 55, ?", "As diferenças entre os termos são quadrados perfeitos. Adicione quadrados consecutivos.", ["91", "85", "90", "80"], "Estas são somas cumulativas de quadrados: 1, 1+4=5, 5+9=14, 14+16=30, 30+25=55, 55+36=91."],
    "TNR4_14": ["O que vem a seguir na string: 2, 4, 12, 48, 240, ?", "Experimente dividir cada termo por 2. Os resultados parecem fatoriais?", ["1440", "1200", "1680", "960"], "Cada termo é 2 × n!: 2×1!=2, 2×2!=4, 2×3!=12, 2×4!=48, 2×5!=240, 2×6!=1440."],
    "TNR4_15": ["O que vem a seguir na string: 6, 13, 27, 55, 111, ?", "Dobre o termo anterior e adicione uma constante em cada etapa.", ["223", "222", "220", "225"], "Cada termo segue a regra: anterior × 2 + 1. O próximo termo é 111 × 2 + 1 = 223."],
    "TNR4_16": ["O que vem a seguir na string: 10, 11, 14, 20, 30, ?", "As diferenças entre os termos são números triangulares: 1, 3, 6, 10,…", ["45", "40", "42", "50"], "As diferenças são 1, 3, 6, 10 – números triangulares. O próximo número triangular é 15, então 30 + 15 = 45."],
    "TNR4_17": ["O que vem a seguir na string: 12, 20, 30, 42, 56, ?", "Tente expressar cada termo como um produto de dois números inteiros consecutivos.", ["72", "68", "70", "64"], "Estes são n(n+1) números oblongos: 3×4=12, 4×5=20, 5×6=30, 6×7=42, 7×8=56, 8×9=72."],
    "TNR4_18": ["O que vem a seguir na string: 1, 9, 36, 100, 225, ?", "Cada termo é o quadrado de um número triangular ou, equivalentemente, a soma cúbica cumulativa.", ["441", "400", "440", "450"], "Estas são somas de cubos consecutivos: 1³=1, 1+8=9, 9+27=36, 36+64=100, 100+125=225, 225+216=441."],
    "TNR4_19": ["O que vem a seguir na string: 3, 7, 19, 55, 163, ?", "Multiplique o termo anterior por um número e subtraia uma constante.", ["487", "489", "485", "492"], "Cada termo segue a regra: anterior × 3 − 2. O próximo termo é 163 × 3 − 2 = 487."],
    "TNR4_20": ["O que vem a seguir na string: 12, 23, 45, 89, 177, ?", "Duplique o termo anterior e faça um pequeno ajuste.", ["353", "354", "355", "350"], "Cada termo segue a regra: anterior × 2 − 1. O próximo termo é 177 × 2 − 1 = 353."],
    "TNR5_01": ["O que vem a seguir na string: 1, 2, 9, 64, 625, ?", "Pense em quanta força a base é elevada em cada posição.", ["7776", "7774", "7200", "3125"], "Cada termo é n elevado à potência (n−1): 1⁰=1, 2¹=2, 3²=9, 4³=64, 5⁴=625, 6⁵=7776."],
    "TNR5_02": ["O que vem a seguir na string: 2, 10, 30, 68, 130, ?", "Tente dividir cada termo em uma parte cúbica e uma parte linear.", ["222", "220", "218", "216"], "Cada termo é n³ + n: 1+1=2, 8+2=10, 27+3=30, 64+4=68, 125+5=130, 216+6=222."],
    "TNR5_03": ["O que vem a seguir na string: 1, 1, 2, 5, 14, ?", "Estes são os números catalães. Cada C(n) = C(0)C(n−1) + C(1)C(n−2) +… + C(n−1)C(0).", ["42", "28", "35", "48"], "Números catalães: C(0)=1, C(1)=1, C(2)=2, C(3)=5, C(4)=14, C(5)=42."],
    "TNR5_04": ["O que vem a seguir na string: 1, 5, 12, 22, 35, ?", "As diferenças são 4, 7, 10, 13 — progressão aritmética na etapa 3.", ["51", "48", "50", "55"], "Estes são números pentagonais: n(3n−1)/2. Para n=6: 6×17/2 = 51."],
    "TNR5_05": ["O que vem a seguir na string: 2, 5, 13, 35, 97, ?", "Tente expressar cada termo como uma soma de duas exponenciais.", ["275", "265", "270", "280"], "Cada termo é 2ⁿ + 3ⁿ (começando em n=0): 1+1=2, 2+3=5, 4+9=13, 8+27=35, 16+81=97, 32+243=275."],
    "TNR5_06": ["O que vem a seguir na string: 1, 5, 17, 53, 161, ?", "Multiplique o termo anterior por 3 e adicione uma pequena constante.", ["485", "483", "322", "487"], "Cada termo segue a regra: anterior × 3 + 2. O próximo termo é 161 × 3 + 2 = 485."],
    "TNR5_07": ["O que vem a seguir na string: 1, 2, 5, 12, 27, ?", "Pense em potências de 2 e subtraia algo que depende da posição.", ["58", "54", "56", "60"], "Cada termo é 2ⁿ − n: 2¹−1=1, 2²−2=2, 2³−3=5, 2⁴−4=12, 2⁵−5=27, 2⁶−6=58."],
    "TNR5_08": ["O que vem a seguir na string: 2, 12, 36, 80, 150, ?", "Tente fatorar cada termo como n² multiplicado por alguma coisa.", ["252", "240", "250", "260"], "Cada termo é n²(n+1): 1×2=2, 4×3=12, 9×4=36, 16×5=80, 25×6=150, 36×7=252."],
    "TNR5_09": ["O que vem a seguir na string: 1, 6, 15, 28, 45, ?", "As diferenças são 5, 9, 13, 17 – aumentam em 4. Esses são números hexadecimais.", ["66", "60", "63", "70"], "Números hexagonais: n(2n−1). Para n=6: 6×11 = 66."],
    "TNR5_10": ["O que vem a seguir na string: 2, 6, 15, 40, 145, ?", "Tente dividir cada termo em uma parte fatorial e uma parte quadrática.", ["756", "750", "745", "760"], "Cada termo é n! + n²: 1!+1=2, 2!+4=6, 3!+9=15, 4!+16=40, 5!+25=145, 6!+36=756."],
    "TNR5_11": ["O que vem a seguir na string: 2, 4, 7, 14, 17, ?", "As operações alternam entre duas regras diferentes em etapas pares e ímpares.", ["34", "20", "31", "37"], "O padrão alterna: ×2, +3, ×2, +3, ×2. Então 17 × 2 = 34."],
    "TNR5_12": ["O que vem a seguir na string: 1, 5, 19, 65, 211, ?", "Expresse cada termo como a diferença de duas exponenciais.", ["665", "660", "633", "670"], "Cada termo é 3ⁿ − 2ⁿ: 3−2=1, 9−4=5, 27−8=19, 81−16=65, 243−32=211, 729−64=665."],
    "TNR5_13": ["O que vem a seguir na string: 1, 4, 11, 29, 76, ?", "Cada termo depende dos dois anteriores. Experimente uma combinação linear.", ["199", "197", "200", "228"], "A regra é a(n) = 3×a(n−1) − a(n−2): 3×29−11=76, 3×76−29=199."],
    "TNR5_14": ["O que vem a seguir na string: 20, 22, 26, 34, 50, ?", "As diferenças são 2, 4, 8, 16 – potências de 2.", ["82", "66", "80", "84"], "As diferenças são potências de 2: 2, 4, 8, 16. A próxima diferença é 32, então 50 + 32 = 82."],
    "TNR5_15": ["O que vem a seguir na string: 1, 4, 10, 20, 35, ?", "Estes são números tetraédricos – somas de números triangulares consecutivos.", ["56", "50", "55", "60"], "Números tetraédricos: n(n+1)(n+2)/6. Para n=6: 6×7×8/6 = 56."],
    "TNR5_16": ["O que vem a seguir na string: 1, 13, 37, 73, 121, ?", "As diferenças são 12, 24, 36, 48 – múltiplos de 12.", ["181", "169", "175", "193"], "Estes são números de estrelas: 6n(n−1)+1. Para n=6: 6×30+1 = 181."],
    "TNR5_17": ["O que vem a seguir na string: 1, 7, 19, 37, 61, ?", "As diferenças são 6, 12, 18, 24 – múltiplos de 6.", ["91", "85", "90", "97"], "Estes são números hexagonais centrados: 3n(n−1)+1. Para n=6: 3×30+1 = 91."],
    "TNR5_18": ["O que vem a seguir na string: 3, 8, 17, 32, 57, ?", "Tente expressar cada termo como a soma de um quadrado e uma potência de 2.", ["100", "96", "98", "105"], "Cada termo é n² + 2ⁿ: 1+2=3, 4+4=8, 9+8=17, 16+16=32, 25+32=57, 36+64=100."],
    "TNR5_19": ["O que vem a seguir na string: 1, 4, 8, 11, 22, ?", "Duas operações diferentes se alternam. Um acrescenta, o outro multiplica.", ["25", "44", "24", "26"], "O padrão alterna: +3, ×2, +3, ×2, +3. Então 22 + 3 = 25."],
    "TNR5_20": ["O que vem a seguir na string: 1, 1, 3, 5, 11, ?", "Cada termo usa os dois termos anteriores com pesos diferentes.", ["21", "16", "22", "19"], "A regra é a(n) = a(n−1) + 2×a(n−2): 5 + 2×3 = 11, 11 + 2×5 = 21."],
    "TLR1_01": ["Todos os médicos são profissionais. Dr. Adams é médico. Que conclusão você pode tirar?", "Se todos os X são Y e Z é X, então Z é Y.", ["Dr. Adams é profissional", "Dr. Adams não é um profissional", "Alguns profissionais não são médicos", "Todos os profissionais são médicos"], "Todos os médicos são profissionais, e o Dr. Adams é médico, então o Dr. Adams é um profissional. Este é um silogismo afirmativo universal direto."],
    "TLR1_02": ["Todos os leões são animais. Simba é um leão. Que conclusão você pode tirar?", "Se todos os membros do grupo X pertencerem ao grupo Y e Simba estiver no X…", ["Simba é um animal", "Todos os animais são leões", "Simba não é um animal", "Alguns animais não são leões"], "Todos os leões são animais, Simba é um leão, então Simba é um animal."],
    "TLR1_03": ["Todas as laranjas são frutas. Este objeto é uma laranja. Que conclusão você pode tirar?", "Se alguma laranja é uma fruta, e este objeto é uma laranja…", ["Este objeto é fruta", "Todas as frutas são laranjas", "Este objeto é vegetal", "Este item pode não ser fruta"], "Todas as laranjas são frutas, esse objeto é uma laranja, então é uma fruta."],
    "TLR1_04": ["Todos os carros são veículos. Um BMW é um carro. Que conclusão você pode tirar?", "Os carros são um subconjunto de veículos. Onde a BMW se encaixa?", ["A BMW é um veículo", "Todos os veículos são carros", "A BMW não é um veículo", "Alguns veículos não são carros"], "Todos os carros são veículos, BMW é carro, portanto BMW é veículo."],
    "TLR1_05": ["Nenhum pássaro é inseto. Um melro é um pássaro. Que conclusão você pode tirar?", "Se nenhum X é Y e o melro é X…", ["Um melro não é inseto", "Um melro é inseto", "Alguns insetos são pássaros", "Todos os melros são insetos"], "Nenhum pássaro é inseto; como o melro é pássaro, não pode ser inseto."],
    "TLR1_06": ["Qualquer gelo está frio. O cubo sobre a mesa é feito de gelo. Que conclusão você pode tirar?", "Se tudo o que é gelo estiver frio e o cubo for gelo…", ["O cubo está frio", "O cubo está quente", "Nem todo gelo é frio", "A mesa está fria"], "Qualquer gelo está frio, o cubo é gelo, então o cubo está frio."],
    "TLR1_07": ["Todos os violinos são instrumentos musicais. Um Stradivarius é um violino. Que conclusão você pode tirar?", "Os violinos fazem parte de uma infinidade de instrumentos. Stradivarius é…", ["Stradivarius é um instrumento", "Todos os instrumentos são violinos", "Stradivarius não é um instrumento", "Alguns instrumentos não podem ser tocados"], "Todos os violinos são instrumentos, o Stradivarius é um violino, então o Stradivarius é um instrumento."],
    "TLR1_08": ["Todas as rosas são plantas. Este exemplar é rosa. Que conclusão você pode tirar?", "As rosas são um subconjunto de plantas. O exemplar é rosa, então…", ["O exemplar é uma planta", "Todas as plantas são rosas", "O espécime não é uma planta", "Rosas não são plantas"], "Todas as rosas são plantas, este exemplar é uma rosa, portanto é uma planta."],
    "TLR1_09": ["Todo ouro é metálico. Este anel é feito de ouro. Que conclusão você pode tirar?", "O ouro é sempre metálico. O anel é de ouro, então...", ["O anel é metálico", "Todos os corpos de metal são dourados", "O anel não é de metal", "O ouro às vezes é não metálico"], "Todo ouro é metálico, o anel é feito de ouro, então o anel é metálico."],
    "TLR1_10": ["Todos os rios contêm água corrente. O Amazonas é um rio. Que conclusão você pode tirar?", "Se todo rio tem água corrente e o Amazonas é um rio…", ["A Amazônia contém água corrente", "Toda água corrente é rio", "A Amazônia não contém água", "Alguns rios estão secos"], "Todos os rios contêm água corrente, o Amazonas é um rio, portanto contém água corrente."],
    "TLR1_11": ["Todos os romances são livros. Todos os livros têm páginas. Que conclusão você pode tirar?", "Conecte os relacionamentos: romances → livros → páginas.", ["Todos os romances têm páginas", "Todas as páginas estão apenas em romeno", "Alguns livros não são romances", "Romances não têm páginas"], "Todos os romances são livros, todos os livros têm páginas, portanto, por transitividade, todos os romances têm páginas."],
    "TLR1_12": ["Todos os chefs sabem cozinhar. Pierre é cozinheiro. Que conclusão você pode tirar?", "Se todo chef sabe cozinhar e Pierre é chef…", ["Pierre sabe cozinhar", "Qualquer um que sabe cozinhar é um chef", "Pierre não sabe cozinhar", "Alguns chefs não sabem cozinhar"], "Todos os chefs sabem cozinhar, Pierre é chef, então Pierre sabe cozinhar."],
    "TLR1_13": ["Todas as águias são pássaros. Todos os pássaros têm penas. Que conclusão você pode tirar?", "Conecte as multidões: águias ⊂ pássaros ⊂ criaturas emplumadas.", ["Todas as águias têm penas", "Todas as criaturas voadoras são águias", "Águias não têm penas", "Alguns pássaros não são águias"], "Todas as águias são aves, todas as aves têm penas, portanto todas as águias têm penas."],
    "TLR1_14": ["Todos os planetas orbitam em torno de uma estrela. Saturno é planeta. Que conclusão você pode tirar?", "Os planetas orbitam estrelas. Saturno é um planeta, então…", ["Saturno orbita uma estrela", "Tudo que orbita uma estrela é um planeta", "Saturno não orbita uma estrela", "A estrela orbita Saturno"], "Todos os planetas orbitam uma estrela, Saturno é um planeta, então Saturno orbita uma estrela."],
    "TLR1_15": ["Todas as baleias são mamíferos. A baleia azul é uma baleia. Que conclusão você pode tirar?", "As baleias são um subconjunto de mamíferos. A baleia azul é uma baleia, então…", ["A baleia azul é um mamífero", "Todos os mamíferos são baleias", "A baleia azul é um peixe", "Algumas baleias não são mamíferos"], "Todas as baleias são mamíferos, a baleia azul é uma baleia, portanto é um mamífero."],
    "TLR1_16": ["Nenhum herbívoro come carne. O coelho é um herbívoro. Que conclusão você pode tirar?", "Se nenhum herbívoro come carne e o coelho é um herbívoro…", ["O coelho não come carne", "O coelho come carne", "Alguns herbívoros comem carne", "Todos os carnívoros são coelhos"], "Herbívoros não comem carne, o coelho é herbívoro, então não come carne."],
    "TLR1_17": ["Todos os filhotes são cachorros. Todos os cães são canídeos. Que conclusão você pode tirar?", "Cadeia: filhotes ⊂ cães ⊂ canídeos.", ["Todos os filhotes são canídeos", "Todos os canídeos são filhotes", "Filhotes não são caninos", "Alguns cães não são canídeos"], "Todos os cachorros são cachorros, todos os cachorros são canídeos, então todos os cachorros são canídeos."],
    "TLR1_18": ["Todos os professores trabalham na educação. O Sr. Brown é professor. Que conclusão você pode tirar?", "Se todo professor trabalhar na educação e o Sr. Brown for professor…", ["Sr. Brown trabalha na educação", "Todo mundo na educação é professor", "Sr. Brown não trabalha na educação", "Alguns professores não trabalham na educação"], "Todos os professores trabalham na educação, o Sr. Brown é professor, então ele trabalha na educação."],
    "TLR1_19": ["Todos os diamantes são pedras preciosas. Todas as joias são valiosas. Que conclusão você pode tirar?", "Corrente: Diamantes ⊂ Gemas ⊂ Objetos de valor.", ["Todos os diamantes são valiosos", "Todas as coisas valiosas são diamantes", "Diamantes não são valiosos", "Algumas joias não valem nada"], "Todos os diamantes são pedras preciosas, são valiosos, portanto todos os diamantes são valiosos."],
    "TLR1_20": ["Todos os dias de verão são quentes. Hoje é um dia de verão. Que conclusão você pode tirar?", "Se todo dia de verão é quente e hoje é dia de verão…", ["Hoje está quente", "Todos os dias quentes são verão", "Está frio hoje", "Os dias de verão nem sempre são quentes"], "Todos os dias de verão são quentes, hoje é dia de verão, então hoje está quente."],
    "TLR2_01": ["Se nevar, a temperatura está abaixo de zero. Neve. Que conclusão você pode tirar?", "Modus ponens: se P→Q e P são verdadeiros, então Q é verdadeiro.", ["A temperatura está abaixo de zero", "A temperatura está acima de zero", "Não está nevando", "Nenhuma conclusão pode ser tirada"], "Modus ponens: P→Q (neve → abaixo de zero). P é verdadeiro, então Q é verdadeiro."],
    "TLR2_02": ["Se você estudar regularmente, suas notas melhoram. Suas notas não melhoraram. Que conclusão você pode tirar?", "Modus tollens: se P→Q e Q são falsos, então P é falso.", ["Você não estudou regularmente", "Você estudou regularmente", "Notas melhoradas", "O aprendizado não influencia as notas"], "Modus tollens: P→Q (aprendizagem → melhores notas). Q é falso, então P é falso."],
    "TLR2_03": ["Se o telefone estiver totalmente carregado, dura o dia todo. Seu telefone está totalmente carregado. Que conclusão você pode tirar?", "O antecedente é verdadeiro – o modus ponens se aplica.", ["O telefone vai durar o dia todo", "O telefone não vai durar o dia todo", "O telefone não está carregado", "Nenhuma conclusão pode ser tirada"], "Modus ponens: P→Q (carregado → segurar o dia). P é verdadeiro, então Q é verdadeiro."],
    "TLR2_04": ["Se o alarme estiver definido, ele toca às 7h. O alarme não tocou às 7. Que conclusão você pode tirar?", "O consequente é falso – aplica modus tollens.", ["O alarme não foi definido", "O alarme foi definido", "O alarme disparou às 7", "O alarme está quebrado"], "Modus tollens: P → Q (pendurar → anel). Q é falso, então P é falso."],
    "TLR2_05": ["Se você tiver a chave certa, a fechadura abre. Você tem a chave certa. Que conclusão você tira?", "O antecedente vale — modus ponens.", ["A fechadura abre", "A fechadura não abre", "Você não tem a chave certa", "A fechadura está travada"], "Modus ponens: P→Q (chave certa → abre). P é verdadeiro, logo Q é verdadeiro."],
    "TLR2_06": ["Se a energia estiver ligada, o refrigerador funciona. A geladeira não funciona. Que conclusão você pode tirar?", "O consequente é falso – aplica modus tollens.", ["A corrente não está ligada", "A corrente está ligada", "A geladeira está funcionando", "Nenhuma conclusão pode ser tirada"], "Modus tollens: P→Q (atual → indo). Q é falso, então P é falso."],
    "TLR2_07": ["Se você regar as plantas diariamente, elas permanecerão verdes. Use-os diariamente. Que conclusão você pode tirar?", "A condição foi atendida – o que vem a seguir?", ["Suas plantas permanecem verdes", "As plantas murcham", "Não os use", "Regar não tem efeito"], "Modus ponens: P→Q (rega diária → verduras). P é verdadeiro, então Q é verdadeiro."],
    "TLR2_08": ["Se o carro tiver combustível, o motor pode dar partida. O motor não dá partida. Que conclusão você pode tirar?", "O resultado não ocorreu – aplique modus tollens.", ["O carro não tem combustível", "O carro tem combustível", "O motor deu partida", "Nenhuma conclusão pode ser tirada"], "Modus tollens: P→Q (combustível → partida). Q é falso, então P é falso."],
    "TLR2_09": ["Se você comprar uma passagem, poderá entrar no trem. Você comprou um ingresso. Que conclusão você pode tirar?", "Você atendeu à condição – o que vem a seguir?", ["Você pode entrar no trem", "Você não pode entrar no trem", "Você não comprou um ingresso", "O trem foi cancelado"], "Modus ponens: P→Q (bilhete → subidas). P é verdadeiro, então Q é verdadeiro."],
    "TLR2_10": ["Se você tiver um passaporte válido, poderá cruzar a fronteira. Você não pode cruzar a fronteira. Que conclusão você pode tirar?", "Se P→Q e Q forem falsos, o que isso significa para P?", ["Você não tem um passaporte válido", "Você tem um passaporte válido", "Você cruzou a fronteira", "Não é necessário passaporte"], "Modus tollens: P→Q (passaporte → passe). Q é falso, então P é falso."],
    "TLR2_11": ["Se um animal for um cavalo, ele terá quatro patas. Este animal tem quatro patas. Que conclusão você pode tirar?", "A verdade do consequente não prova o antecedente. Muitos animais têm quatro patas.", ["Não podemos concluir que é um cavalo", "Definitivamente é um cavalo", "Tem duas pernas", "Não é um animal"], "Falácia de afirmar o consequente: P→Q e Q não resultam em P. Muitos animais que não são cavalos têm quatro patas."],
    "TLR2_12": ["Se alguém é advogado, estudou Direito. Sam estudou direito. Que conclusão você pode tirar?", "Só porque Q é verdadeiro, não significa que P seja verdadeiro.", ["Não podemos concluir que Sam é advogado", "Sam é definitivamente um advogado", "Sam não estudou direito", "Todos aqueles que estudaram direito são advogados"], "Declaração do consequente: De P → Q (advogado → estudou direito) e Q não se segue que Sam seja advogado."],
    "TLR2_13": ["Se o forno estiver ligado, a cozinha aquece. A cozinha não está quente. Que conclusão você pode tirar?", "O consequente é falso – modus tollens.", ["O forno não está aceso", "O forno está ligado", "A cozinha está quente", "Nenhuma conclusão pode ser tirada"], "Modus tollens: P→Q (forno → quente). Q é falso, então P é falso."],
    "TLR2_14": ["Se você pisar no freio, o carro desacelera. Você pisou no freio. Que conclusão você pode tirar?", "O antecedente é verdadeiro – modus ponens.", ["O carro desacelera", "O carro acelera", "Você não pisou no freio", "Nada acontece"], "Modus ponens: P→Q (freio → desaceleração). P é verdadeiro, então Q é verdadeiro."],
    "TLR2_15": ["Se nevar, o céu fica nublado. O céu está ficando nublado. Que conclusão você pode tirar?", "Céus nublados podem não ter neve – a afirmação é consistente?", ["Não podemos concluir que está nevando", "Claro que está nevando", "O céu está claro", "Nunca neva quando está nublado"], "Declaração do consequente: P→Q e Q não resultam em P."],
    "TLR2_16": ["Se a bateria estiver carregada, a lanterna funciona. A lanterna não funciona. Que conclusão você pode tirar?", "Q é falso – o que isso diz sobre P?", ["A bateria não está carregada", "A bateria está carregada", "A lanterna funciona", "Nenhuma conclusão pode ser tirada"], "Modus tollens: P→Q (carregado → funcionando). Q é falso, então P é falso."],
    "TLR2_17": ["Se você colocar açúcar no chá, o chá fica doce. Você coloca açúcar no seu chá. Que conclusão você pode tirar?", "A condição é satisfeita – modus ponens.", ["O chá fica doce", "O chá permanece amargo", "Você não adicionou açúcar", "Açúcar não tem efeito"], "Modus ponens: P→Q (açúcar → doce). P é verdadeiro, então Q é verdadeiro."],
    "TLR2_18": ["Se o roteador Wi-Fi estiver ligado, os dispositivos poderão se conectar à Internet. Os dispositivos não conseguem se conectar. Que conclusão você pode tirar?", "Q é falso – modus tollens.", ["O roteador Wi-Fi não está ligado", "O roteador Wi-Fi está ligado", "Dispositivos podem se conectar", "A internet não existe"], "Modus tollens: P→Q (ligado → conectar). Q é falso, então P é falso."],
    "TLR2_19": ["Se o aluno se inscrever no curso, ele receberá o plano de estudos. Emma se matriculou no curso. Que conclusão você pode tirar?", "Emma atendeu à condição – o que vem a seguir?", ["Emma recebe o plano de estudos", "Emma não entende o plano de estudos", "Emma não se inscreveu", "O curso não tem programação"], "Modus ponens: P→Q (escrito → programa). P é verdadeiro para Emma, ​​​​então Q é verdadeiro."],
    "TLR2_20": ["Se for domingo, a loja está fechada. Não é domingo. Que conclusão você pode tirar?", "O antecedente é falso — não informa se Q é verdadeiro (negação do antecedente).", ["Não podemos concluir se a loja está aberta ou fechada", "A loja está definitivamente aberta", "A loja está definitivamente fechada", "Deve ser sábado"], "Negar o antecedente é um erro: nada de certo sobre Q segue de P→Q e do falso P."],
    "TLR3_01": ["Anna é mais alta que Dana. Dana é mais alta que Ben. Ben é mais alto que Carl. Quem é o mais baixo?", "Escreva a cadeia de desigualdades e encontre a “base”.", ["Carlos", "Bem", "Dana", "Ana"], "Anna > Dana > Ben > Carl. Carl é baixo, então o mais baixo."],
    "TLR3_02": ["Felix é mais leve que George. Harry é mais pesado que George. Ivan é mais leve que Felix. Quem é o mais difícil?", "Ordem: Harry > George > Felix > Ivan.", ["Harry", "Jorge", "Félix", "Ivan"], "Harry > Jorge > Félix > Ivan. O mais difícil é Harry."],
    "TLR3_03": ["Mia é mais nova que Nina. Oscar é mais velho que Nina. Pam é mais nova que Mia. Quem é o mais velho?", "Oscar > Nina > Mia > Pam. quem está acordado", ["Óscar", "Nina", "Mia", "Pam"], "Oscar > Nina > Mia > Pam. O mais velho é Oscar."],
    "TLR3_04": ["Numa corrida, Raj termina depois de Sam. Tina terminou antes de Sam. Uma termina depois de Raj. Quem termina primeiro?", "Primeiro por ordem de chegada = melhor assento. Corrente: Tina → Sam → Raj → Uma.", ["Tina", "Sam", "Raj", "Uma"], "Ordem: Tina, Sam, Raj, Uma. A primeira é Tina."],
    "TLR3_05": ["Victor ganha menos que Wendy. Wendy ganha menos que Xavier. Yara ganha mais que Xavier. Quem ganha mais?", "Corrente: Victor < Wendy < Xavier < Yara.", ["Yara", "Xavier", "Wendy", "Victor"], "Yara > Xavier > Wendy > Victor. Yara é a que mais ganha."],
    "TLR3_06": ["Eve tem uma pontuação mais alta que Frank. Grace tem uma pontuação menor que Frank. Dave tem uma pontuação mais alta que Eve. Quem tem a pontuação mais baixa?", "Dave > Eva > Frank > Grace. quem está caído", ["Graça", "Frank", "Eva", "David"], "Dave > Eva > Frank > Grace. Grace tem a pontuação mais baixa."],
    "TLR3_07": ["Lily nada mais rápido que Max. Olivia nada mais rápido que Lily. Noah nada mais devagar que Max. Quem nada mais devagar?", "Por velocidade: Olivia > Lily > Max > Noah.", ["Noé", "Máx.", "Lírio", "Olívia"], "Olivia > Lily > Max > Noah. O mais lento é Noah."],
    "TLR3_08": ["Quinn é mais baixa que Ruth. Steve é ​​mais alto que Tom. Tom é mais alto que Ruth. Quem é o mais alto?", "Corrente: Steve > Tom > Ruth > Quinn.", ["Steve", "Tom", "Rute", "Quinn"], "Steve > Tom > Ruth > Quinn. O mais alto é Steve."],
    "TLR3_09": ["Amy pesa menos que Brian. Clara pesa mais que Dan. Dan pesa mais que Brian. Quem é o mais fácil?", "Clara > Dan > Brian > Amy.", ["Amém", "Brian", "Dan", "Clara"], "Clara > Dan > Brian > Amy. A mais fácil é Amy."],
    "TLR3_10": ["Jake corre mais devagar que Kim. Leo corre mais rápido que Mona. Mona corre mais rápido que Kim. Quem é o segundo mais rápido?", "Leo > Mona > Kim > Jake. Segundo?", ["Mona", "Kim", "Leão", "Jack"], "Leo > Mona > Kim > Jake. A segunda em velocidade é Mona."],
    "TLR3_11": ["Num grupo de 20 alunos, 12 jogam tênis e 10 jogam futebol. Todo mundo pratica pelo menos um esporte. Quantos fazem os dois?", "Ambos = A + B − total (quando cada um fizer pelo menos um).", ["2", "4", "8", "10"], "12 + 10 − 20 = 2. Dois alunos praticam os dois esportes."],
    "TLR3_12": ["Num grupo de 25 pessoas, 18 gostam de café e 13 gostam de chá. Todo mundo gosta de pelo menos um. Quantas pessoas gostam dos dois?", "Ambos = café + chá – total.", ["6", "5", "7", "8"], "18 + 13 − 25 = 6. Seis pessoas gostam de ambos."],
    "TLR3_13": ["Numa empresa com 35 funcionários, 20 falam francês e 22 alemão. Todo mundo fala pelo menos um. Quantos ambos falam?", "Ambos = Francês + Alemão − total.", ["7", "5", "8", "13"], "20 + 22 − 35 = 7. Sete funcionários falam ambos."],
    "TLR3_14": ["Num grupo de 40 turistas, 28 visitaram o museu e 18 o parque. Todos visitaram pelo menos um lugar. Quantos visitaram ambos?", "Ambos = museu + parque − total.", ["6", "10", "8", "4"], "28 + 18 − 40 = 6. Seis turistas visitaram ambos."],
    "TLR3_15": ["Num grupo de 30 leitores, 16 leem ficção e 20 leem não-ficção. Todo mundo lê pelo menos um tipo. Quantos leem ambos?", "Ambos = ficção + não ficção − total.", ["6", "4", "10", "14"], "16 + 20 − 30 = 6. Seis leitores leem ambos."],
    "TLR3_16": ["Na sequência, Alice é a 3ª da esquerda e a 5ª da direita. Quantas pessoas estão na fila?", "Total = posição esquerda + posição direita − 1.", ["7", "8", "6", "9"], "3 + 5 − 1 = 7. São 7 pessoas."],
    "TLR3_17": ["Em sequência, Bob é o 7º da esquerda e o 4º da direita. Quantas pessoas existem?", "Total = esquerda + direita − 1.", ["10", "11", "9", "12"], "7 + 4 − 1 = 10. São 10 pessoas."],
    "TLR3_18": ["Na sequência, Carol está em 5º na frente e 9º atrás. Quantas pessoas estão na fila?", "Total = frente + verso − 1.", ["13", "14", "12", "15"], "5 + 9 − 1 = 13. São 13 pessoas."],
    "TLR3_19": ["Consecutivamente, David é o 9º na frente e o 3º atrás. Quantas pessoas existem?", "Total = frente + verso − 1.", ["11", "12", "10", "13"], "9 + 3 − 1 = 11. São 11 pessoas."],
    "TLR3_20": ["Consecutivamente, Emily é a 6ª da esquerda e a 6ª da direita. Quantas pessoas existem?", "Total = esquerda + direita − 1.", ["11", "12", "10", "13"], "6 + 6 − 1 = 11. São 11 pessoas."],
    "TLR4_01": ["Cinco pessoas são comparadas por peso. E é mais difícil que A, A que B, C que D, D que B, A que C. Classifique do mais pesado ao mais leve.", "Construa a cadeia: E > A > C > D > B.", ["E, A, C, D, B", "E, A, D, C, B", "A, E, C, D, B", "E, C, A, D, B"], "E > A > C > D > B. O mais difícil é E, o mais fácil é B."],
    "TLR4_02": ["Cinco corredores terminam uma corrida. Sam termina antes de Priya, Priya antes de Quinn, Quinn antes de Tara, Tara antes de Rosa. Quem termina em 3º lugar?", "Ordem de chegada: Sam → Priya → Quinn → Tara → Rosa.", ["Quinn", "Priya", "país", "Sam"], "Sam, Priya, Quinn, Tara, Rosa. O terceiro é Quinn."],
    "TLR4_03": ["Cinco alunos têm pontuações diferentes. Jack > Fred > Gina > Iris > Hank. Quem tem a segunda pontuação mais baixa (penúltimo lugar)?", "Número de baixo para cima: Hank, Iris…", ["Íris", "Gina", "Hank", "Fred"], "Em segundo lugar (depois de Hank) está Iris."],
    "TLR4_04": ["Seis atletas por velocidade: Elena > Diana > Ava > Bella > Chloe > Fiona. Classifique do mais rápido para o mais lento.", "Construa passo a passo.", ["Elena, Diana, Ava, Bella, Chloe, Fiona", "Diana, Elena, Ava, Bella, Chloe, Fiona", "Elena, Ava, Diana, Bella, Chloe, Fiona", "Elena, Diana, Bella, Ava, Chloe, Fiona"], "Elena > Diana > Ava > Bella > Chloe > Fiona."],
    "TLR4_05": ["Cinco cidades por população: Penny > Liam > Mason > Oliver > Noah. Classifique do mais populoso para o menos populoso.", "Penny > Liam > Mason > Oliver > Noah.", ["Penny, Liam, Mason, Oliver, Noah", "Liam, Penny, Mason, Oliver, Noah", "Penny, Mason, Liam, Oliver, Noah", "Penny, Liam, Oliver, Mason, Noah"], "Penny > Liam > Mason > Oliver > Noah."],
    "TLR4_06": ["Em uma empresa com 60 funcionários, 38 usam Windows e 30 usam Mac. Todo mundo usa pelo menos um sistema. Quantos usam ambos?", "Ambos = Windows + Mac – total.", ["8", "10", "12", "6"], "38 + 30 − 60 = 8."],
    "TLR4_07": ["Numa escola com 80 alunos, 55 estudam matemática e 42 ciências. Todo mundo estuda pelo menos uma matéria. Quantos estudam ambos?", "Ambos = matemática + ciências - total.", ["17", "15", "20", "23"], "55 + 42 − 80 = 17."],
    "TLR4_08": ["Num clube com 75 sócios, 50 jogam xadrez e 40 damas. Todo mundo joga pelo menos um jogo. Quantos jogam ambos?", "Ambos = damas + damas - total.", ["15", "10", "20", "25"], "50 + 40 − 75 = 15."],
    "TLR4_09": ["Em uma pesquisa realizada com 90 pessoas, 60 preferem chocolate e 52 baunilha. Todo mundo gosta de pelo menos um sabor. Quantas pessoas gostam dos dois?", "Ambos = chocolate + baunilha – total.", ["22", "18", "30", "12"], "60 + 52 − 90 = 22."],
    "TLR4_10": ["Num grupo de 100 eleitores, 72 apoiam a proposição A e 65 apoiam a proposição B. Cada um apoia pelo menos uma. Quantos apoiam ambos?", "Ambos = A + B - total.", ["37", "35", "40", "28"], "72 + 65 − 100 = 37."],
    "TLR4_11": ["Numa pesquisa, 50 pessoas: 30 têm carro, 25 têm bicicleta e 10 ambos. Quantos não têm nenhum?", "Pelo menos um = carro + bicicleta – ambos. Nenhum = total - pelo menos um.", ["5", "10", "15", "0"], "30 + 25 − 10 = 45 têm pelo menos um. 50 − 45 = 5 não tem nenhum."],
    "TLR4_12": ["Em uma turma de 45 alunos, 28 foram aprovados em matemática, 20 em ciências e 8 em ambas. Quantos passaram exatamente em uma matéria?", "Apenas um = (somente matemática) + (somente ciências).", ["32", "40", "28", "20"], "Somente matemática: 28−8=20. Apenas ciência: 20−8=12. Total 32."],
    "TLR4_13": ["60 pessoas: 40 tocam violão, 30 tocam piano, todos tocam pelo menos um instrumento. Quantos cantam exatamente um?", "Ambos = guitarra + piano − 60. Exatamente um = 60 − ambos.", ["50", "60", "40", "30"], "Ambos = 10. Exatamente um = 50."],
    "TLR4_14": ["55 alunos: 32 no círculo de artes, 28 em música, 12 em ambos. Quantos não estão em nenhum círculo?", "Pelo menos um = 32+28−12. Nenhum = 55 - isto.", ["7", "5", "10", "3"], "48 têm pelo menos um círculo. 55−48=7."],
    "TLR4_15": ["70 pessoas: 45 leem jornais, 38 revistas, 20 ambos. Quanto um cara lê exatamente?", "Exatamente um = (apenas jornal) + (apenas revista).", ["43", "63", "50", "33"], "25 + 18 = 43."],
    "TLR4_16": ["Se estiver frio, Tom usa uma jaqueta. Se ele usar jaqueta, leve guarda-chuva. Está frio. o que Tom leva", "Corrente: frio → jaqueta → guarda-chuva. Modus ponens duas vezes.", ["Um guarda-chuva", "Um chapéu", "Nada", "Só a jaqueta"], "Está frio → jaqueta → guarda-chuva. Então leve um guarda-chuva."],
    "TLR4_17": ["Se Alice aprende, ela promove. Se ele passar, ele se forma. Se ele se formar, receberá uma oferta de emprego. Alice está aprendendo. Qual é o resultado final?", "Cadeia: aprendizagem → promoção → graduação → oferta.", ["Alice recebe uma oferta de emprego", "Alice só passa no exame", "Alice acabou de se formar", "Nenhuma conclusão pode ser tirada"], "Alice percorre toda a cadeia até a oferta de emprego."],
    "TLR4_18": ["Se houver falta de energia, o computador será desligado. Se parar, você perderá o trabalho não salvo. O trabalho não foi perdido. Que conclusão você tira?", "Modus tollens em cadeia.", ["A corrente não caiu", "A corrente caiu", "O computador parou", "O trabalho está perdido"], "O trabalho não foi perdido → o computador não desligou → a energia não falhou."],
    "TLR4_19": ["Se chover, a partida será cancelada. Se for cancelado, os ingressos serão devolvidos. Os ingressos não foram devolvidos. Que conclusão?", "Não voltou → a partida não foi cancelada → não choveu.", ["Não choveu", "Choveu", "A partida foi cancelada", "Os ingressos foram devolvidos"], "Duplo modus tollens: não chove."],
    "TLR4_20": ["Se você comer muito açúcar, ganhará peso. Se você ganhar peso, precisará de exercícios. Se precisar, você entra na academia. Você não se inscreveu na academia. Que conclusão?", "Modus tollens em cadeia.", ["Você não comeu muito açúcar", "Você comeu muito açúcar", "Você ganhou peso", "Você se inscreveu na academia"], "Sem academia → sem necessidade extra → sem engorda → sem excesso de açúcar."],
    "TLR5_01": ["Três pessoas: A, B e C. Exatamente uma diz a verdade. A diz: «B e C mentem os dois». B diz: «A mente». C diz: «A diz a verdade». Quem diz a verdade?", "Imagine, por ordem, que só essa pessoa diz a verdade e veja se há contradições.", ["B", "A", "C", "Nenhum"], "Se B diz a verdade: A mente, então não é verdade que B e C mintam os dois — B é sincero ✓. C mente, logo A não diz a verdade ✓. Só B é coerente."],
    "TLR5_02": ["Três pessoas: D, E e F. Exatamente uma diz a verdade. D diz: «E mente». E diz: «F mente». F diz: «D e E mentem os dois». Quem diz a verdade?", "Teste cada pessoa como a única veraz.", ["E", "D", "F", "Nenhum"], "Se E diz a verdade: F mente ✓. D diz «E mente» — isso é falso, logo D mente ✓. F mente ao dizer que D e E mentem os dois, o que fecha. Só E é coerente."],
    "TLR5_03": ["G, H, I – suspeitos. Apenas um culpado. O culpado sempre mente; os inocentes dizem a verdade. G: “Ele é culpado”. H: “Eu não sou culpado”. Eu: \"G é culpado\". Quem é o culpado?", "Adivinhe quem é o culpado.", ["G", "H", "eu", "Não pode ser determinado"], "Se G é culpado: G mente → H inocente ✓; H e eu dizemos a verdade ✓. O resto leva a contradições."],
    "TLR5_04": ["J, K, L. Exatamente um diz a verdade. J: “Eu digo a verdade”. K: «J diz a verdade». L: \"Estou mentindo.\" Quem está dizendo a verdade?", "Se J fosse honesto, K também seria honesto – impossível.", ["eu", "J.", "K", "Nenhum"], "L honesto → J mentiroso → K mentiroso ✓. Apenas L funciona."],
    "TLR5_05": ["M, N, O. Exatamente um diz a verdade. M: «N e O dizem a verdade». N: “Estou mentindo”. O: \"Eu não me importo\". Quem está dizendo a verdade?", "Se M fosse honesto, N e O seriam ambos honestos - contradiz \"exatamente um\".", ["N", "eu", "ah", "Nenhum"], "N honesto → M mentiroso; A afirmação de M é falsa → nem ambas N,O honesto → O está mentindo ✓."],
    "TLR5_06": ["Em três dias será quarta-feira. que dia é hoje", "Conte três dias a partir de quarta-feira.", ["domingo", "Segunda-feira", "Sábado", "Terça-feira"], "Quarta-feira −3 dias = domingo."],
    "TLR5_07": ["Ontem foi sexta-feira. Que dia será depois de amanhã?", "Descubra hoje e depois +2 dias.", ["Segunda-feira", "domingo", "Terça-feira", "Sábado"], "Ontem sexta → hoje sábado → depois de amanhã segunda."],
    "TLR5_08": ["Há dois dias era segunda-feira. Que dia será daqui a três dias?", "Descubra «hoje» de «dois dias atrás» e depois +3.", ["Sábado", "Sexta-feira", "domingo", "Quinta-feira"], "Dois dias atrás = segunda → hoje = quarta → daqui a três dias = sábado."],
    "TLR5_09": ["Anteontem foi quinta-feira. Que dia será amanhã?", "Anteontem = dois dias atrás.", ["Domingo", "Sábado", "Segunda-feira", "Sexta-feira"], "Anteontem quinta → ontem sexta → hoje sábado → amanhã domingo."],
    "TLR5_10": ["Em quatro dias será terça-feira. que dia foi ontem", "Hoje = terça-feira − 4 dias; ontem = hoje − 1.", ["Quinta-feira", "Sexta-feira", "Quarta-feira", "Sábado"], "Hoje = sexta-feira, ontem = quinta-feira."],
    "TLR5_11": ["Seis alunos por série: Fay > Diana > Abby > Brian > Carl > Elena. Quem é o terceiro mais alto (terceiro mais alto)?", "Número superior: 1 Fay, 2 Diana, 3…", ["Abby", "Diana", "Brian", "Faye"], "A terceira é Abby."],
    "TLR5_12": ["Cinco frascos: 5>1>2>4>3 em peso. Qual deles está no meio (3º lugar)?", "Cadeia completa 5>1>2>4>3.", ["Frasco 2", "Frasco 1", "Frasco 4", "Frasco 3"], "O terceiro na ordem é o frasco 2."],
    "TLR5_13": ["Sete pessoas por idade: T>U>V>W>X>Y>Z. Quem tem o quarto ano de idade?", "Posição numérica 4 na cadeia.", ["o que", "V", "X", "você"], "O quarto é W."],
    "TLR5_14": ["Cinco cidades: E>A>B>D>C por população. Qual é o menos povoado?", "C está no final da cadeia.", ["Cidade C", "Cidade D", "Cidade B", "Cidade A"], "O menor é C."],
    "TLR5_15": ["Seis cartas por páginas: T>P>Q>U>R>S. Qual tem o penúltimo menor número de páginas (penúltima)?", "Inferior: S mínimo, depois R.", ["Livro R", "Livro S", "O livro U", "O livro Q"], "O segundo de baixo é R."],
    "TLR5_16": ["Três caixas: «Maçãs», «Laranjas», «Mistura». Todos os rótulos estão errados. Retire uma maçã da caixa «Mistura». O que realmente há na caixa chamada “Maçãs”?", "“Mistura” é falsa – a caixa é homogênea; você tirou uma maçã → aí estão as maçãs.", ["Laranjas", "Maçãs", "Mistura", "Não pode ser determinado"], "A caixa “Mix” contém apenas maçãs. «Laranja» não tem laranja → mistura. \"Apple\" tem laranjas."],
    "TLR5_17": ["Alice, Bob, Carol trabalham em dias diferentes: segunda, terça, quarta. Alice não trabalha às segundas-feiras. Bob não trabalha às terças ou quartas. Carol não trabalha às quartas-feiras. Em que dia Carol trabalha?", "Tudo começa com Bob – ele tem o único dia possível.", ["Terça-feira", "Segunda-feira", "Quarta-feira", "Não pode ser determinado"], "Bob só às segundas → Alice às terças ou quartas → Carol não às quartas → Carol às terças."],
    "TLR5_18": ["Se P for verdadeiro, Q é verdadeiro. Se Q for verdadeiro, R é falso. Se R for falso, S é verdadeiro. P é verdade. É verdadeiro ou falso?", "Percorra a cadeia P→Q→¬R→S.", ["É verdade", "É falso", "S é desconhecido", "S depende de R"], "P → Q → R falso → S verdadeiro."],
    "TLR5_19": ["Cinco amigos: Alex > Drew > Blake > Casey > Ellie por idade. Quem está no meio (terceiro de idade)?", "O terceiro de cinco.", ["Blake", "desenhou", "Casey", "Alex"], "O terceiro é Blake."],
    "TLR5_20": ["Na classificação V,W,X,Y,Z: V antes de W; X imediatamente após Y; Z em 3º lugar; W em 5º lugar; Y antes de Z. Em que lugar está V?", "Z=3, W=5; Y antes de Z; X depois de Y.", ["4º lugar", "1º lugar", "2º lugar", "3º lugar"], "Y=1, X=2, Z=3, V=4, W=5."],
    "TSR1_01": ["Quantos lados tem um pentágono?", "O prefixo \"penta-\" refere-se a um número específico.", ["5", "4", "6", "7"], "\"Pentágono\" vem do grego para cinco. Um pentágono tem exatamente 5 lados."],
    "TSR1_02": ["Quantos lados tem um hexágono?", "O prefixo “hexa-” indica um número – pense em hexadecimal.", ["6", "5", "8", "7"], "\"Hexágono\" vem do grego para seis. Um hexágono tem 6 lados."],
    "TSR1_03": ["Quantos lados tem um octógono?", "Pense no polvo – quantos braços ele tem?", ["8", "6", "10", "7"], "O prefixo «octa-» significa oito, como em polvo. Um octógono tem 8 lados."],
    "TSR1_04": ["Quantos ângulos um triângulo tem?", "O prefixo «tri-» fornece a resposta diretamente.", ["3", "4", "2", "1"], "Um triângulo tem 3 ângulos – um em cada vértice onde dois lados se encontram."],
    "TSR1_05": ["Quantos ângulos um pentágono tem?", "Cada lado encontra o próximo em um ângulo. Conte os lados.", ["5", "4", "6", "3"], "Qualquer polígono tem tantos ângulos quanto lados. Um pentágono tem 5 lados e 5 ângulos."],
    "TSR1_06": ["Quantas faces tem uma caixa retangular (prisma retangular)?", "Pense em cima, em baixo, na frente, atrás, esquerda e direita.", ["6", "4", "8", "5"], "Um prisma retangular possui 6 faces: superior, inferior, frontal, posterior, esquerda, direita."],
    "TSR1_07": ["Quantos vértices (cantos) um triângulo tem?", "Um vértice é onde dois lados se encontram. Conte os cantos.", ["3", "4", "2", "6"], "Um triângulo tem 3 vértices – um em cada canto."],
    "TSR1_08": ["Qual forma 2D tem exatamente 3 lados e 3 ângulos?", "É um dos polígonos mais simples.", ["Triângulo", "Quadrado", "Pentágono", "Círculo"], "Um triângulo é um polígono com 3 lados e 3 ângulos."],
    "TSR1_09": ["Se você dobrar uma folha de papel ao meio, quantas camadas de papel você terá?", "Antes de dobrar você tem 1 camada. Dobre o número.", ["2", "1", "3", "4"], "Cada dobra ao meio duplica as camadas. A partir de 1, uma dobra dá 2 camadas."],
    "TSR1_10": ["Qual é o formato de cada face de um cubo padrão?", "Todas as faces do cubo são iguais. Qual forma regular tem 4 lados iguais e 4 ângulos retos?", ["Quadrado", "Retângulo", "Triângulo", "Círculo"], "O cubo tem 6 faces e cada uma é um quadrado."],
    "TSR1_11": ["Qual corpo 3D parece igual, não importa como você o corta no centro?", "Não tem arestas, nem picos, é perfeitamente redondo.", ["Esfera", "Cilindro", "Contra", "Cubo"], "A esfera é perfeitamente simétrica. Qualquer corte no centro resulta em um círculo idêntico."],
    "TSR1_12": ["Quantos lados retos tem um círculo?", "O círculo é curvo em todos os lugares. Existem lados retos?", ["0", "1", "2", "Infinito"], "O círculo não tem lados retos – é uma curva contínua sem cantos ou segmentos retos."],
    "TSR1_13": ["Quantos lados tem um triângulo?", "O nome diz: «tri» significa três.", ["3", "2", "4", "5"], "Um triângulo é um polígono com exatamente 3 lados."],
    "TSR1_14": ["Quantos lados tem um quadrado?", "Pense em uma janela ou em um tabuleiro de xadrez.", ["4", "3", "5", "6"], "Um quadrado tem 4 lados iguais e 4 ângulos retos."],
    "TSR1_15": ["Quantos vértices (cantos) um quadrado tem?", "Conte os pontos onde dois lados se encontram.", ["4", "3", "5", "6"], "O quadrado tem 4 vértices – um em cada canto."],
    "TSR1_16": ["Quantos vértices tem um hexágono?", "Um polígono sempre tem tantos vértices quanto lados.", ["6", "5", "8", "4"], "O hexágono tem 6 lados, portanto 6 vértices."],
    "TSR1_17": ["Se você dobrar uma folha ao meio duas vezes, quantas camadas obterá?", "Cada dobra dobra o número atual de camadas.", ["4", "2", "3", "8"], "Primeira dobra: 1 → 2 camadas. Segundo: 2 → 4 camadas."],
    "TSR1_18": ["Qual forma tem 4 lados, todos ângulos de 90° e lados opostos paralelos?", "É o formato mais comum para portas, biombos e livros.", ["Retângulo", "trapézio", "Losango", "Paralelogramo"], "O retângulo tem 4 lados, opostos paralelos, todos os ângulos internos de 90°."],
    "TSR1_19": ["Quantos cantos um retângulo tem?", "Um canto é onde dois lados se encontram em ângulo.", ["4", "2", "3", "5"], "O retângulo possui 4 cantos (vértices), um em cada ângulo reto."],
    "TSR1_20": ["Qual forma 2D tem todos os pontos do contorno à mesma distância do centro?", "Pense em uma moeda vista de cima ou em uma pizza.", ["Círculo", "Elipse", "Quadrado", "Oval"], "Um círculo é o conjunto de pontos equidistantes do centro. Essa distância constante é o raio."],
    "TSR2_01": ["Quantos lados tem um prisma retangular (caixa)?", "Conte as bordas superiores e inferiores da face e as bordas verticais que as conectam.", ["12", "8", "10", "6"], "Prisma retangular: 4 arestas superiores + 4 inferiores + 4 verticais = 12 arestas."],
    "TSR2_02": ["Quantos vértices tem um prisma retangular?", "Conte os cantos superiores e inferiores da face separadamente.", ["8", "6", "10", "12"], "4 pontos para cima + 4 pontos para baixo = 8 pontos."],
    "TSR2_03": ["Quantas faces tem um prisma pentagonal?", "Um prisma de base de n lados possui n faces retangulares laterais mais 2 bases.", ["7", "5", "10", "6"], "2 bases pentagonais + 5 faces retangulares laterais = 7 faces."],
    "TSR2_04": ["Quantas arestas tem um prisma triangular?", "Conte as arestas de cada base triangular e depois as arestas que as conectam.", ["9", "6", "8", "12"], "3 arestas para cima + 3 para baixo + 3 verticais = 9 arestas."],
    "TSR2_05": ["Quantos vértices tem um prisma triangular?", "Cada base triangular traz seus próprios vértices.", ["6", "5", "8", "9"], "3 pontas em cada base: 3 + 3 = 6 pontas."],
    "TSR2_06": ["Se 4 cubos idênticos estão em linha reta, cada um compartilhando uma face com o próximo, quantas faces são visíveis no total (incluindo a parte inferior)?", "Começa com faces 4×6 e depois subtrai as faces ocultas em cada junção.", ["18", "20", "16", "24"], "4 cubos: 24 faces. 3 junções × 2 faces ocultas = 6. 24 - 6 = 18 visíveis."],
    "TSR2_07": ["Quantas faces tem um prisma hexagonal?", "O prisma de base n-gon tem n + 2 faces.", ["8", "6", "12", "10"], "2 bases hexagonais + 6 faces retangulares = 8 faces."],
    "TSR2_08": ["Quantas arestas tem um prisma pentagonal?", "Para um prisma com base de n lados: arestas totais = 3n.", ["15", "10", "12", "20"], "5 para cima + 5 para baixo + 5 verticais = 3 × 5 = 15 arestas."],
    "TSR2_09": ["Quantos vértices tem um prisma pentagonal?", "O prisma duplica os vértices do polígono base.", ["10", "12", "8", "15"], "5 pontas por base × 2 bases = 10 pontas."],
    "TSR2_10": ["Quantas arestas tem uma pirâmide de base quadrada?", "Conte as bordas da base e depois as bordas dos cantos da base até o topo.", ["8", "5", "6", "10"], "4 arestas na base + 4 arestas laterais em direção ao topo = 8 arestas."],
    "TSR2_11": ["Quantos vértices tem uma pirâmide de base quadrada?", "Não se esqueça da dica principal!", ["5", "4", "6", "8"], "4 cantos na base + 1 topo = 5 topos."],
    "TSR2_12": ["Quantas faces tem uma pirâmide de base quadrada?", "Conte a base e cada face lateral triangular.", ["5", "4", "6", "8"], "1 base quadrada + 4 faces triangulares = 5 faces."],
    "TSR2_13": ["Quantas arestas tem um prisma hexagonal?", "Fórmula: arestas = 3 × o número de lados da base.", ["18", "12", "24", "15"], "6 + 6 + 6 = 3 × 6 = 18 arestas."],
    "TSR2_14": ["Quantos vértices tem um prisma hexagonal?", "Cada base hexagonal possui 6 cantos.", ["12", "8", "6", "18"], "6 pontas por base × 2 bases = 12 pontas."],
    "TSR2_15": ["Se 5 cubos idênticos estão alinhados, compartilhando faces, quantas faces ficam visíveis no total (incluindo a parte inferior)?", "5 cubos = 30 faces. Quantas juntas e quantas faces cada uma esconde?", ["22", "20", "24", "26"], "30 faces − 4 juntas × 2 = 30 − 8 = 22 visíveis."],
    "TSR2_16": ["Quantas faces tem um prisma octogonal?", "Fórmula do prisma: n + 2 faces para base de n lados.", ["10", "8", "12", "16"], "2 bases octogonais + 8 faces laterais retangulares = 10 faces."],
    "TSR2_17": ["Quantas arestas tem um prisma octogonal?", "Fórmula: 3n arestas para base com n lados.", ["24", "16", "20", "32"], "3 × 8 = 24 arestas."],
    "TSR2_18": ["Quantos vértices tem uma pirâmide triangular (tetraedro)?", "Base triangular e ponto acima.", ["4", "3", "5", "6"], "Tetraedro: 3 vértices na base + 1 vértice = 4 vértices."],
    "TSR2_19": ["Fórmula de Euler: V − E + F = 2 para poliedros convexos (E = número de arestas). Se um poliedro tem 6 vértices e 12 arestas, quantas faces ele possui?", "Reorganize: F = 2 − V + E.", ["8", "6", "10", "7"], "F = 2 − 6 + 12 = 8 faces (ex.: cubo regular ou octaedro)."],
    "TSR2_20": ["Quantas diagonais tem um quadrado?", "Uma diagonal conecta dois vértices não adjacentes. O quadrado tem 4 vértices.", ["2", "4", "1", "3"], "O quadrado tem 2 diagonais, cada uma conectando cantos opostos."],
    "TSR3_01": ["Um cubo 3×3×3 é pintado em todas as faces e depois cortado em 27 cubos pequenos. Quantos cubos têm pelo menos uma face pintada?", "Apenas o cubo exatamente no centro da grade 3×3×3 não tem tinta. Quantos cubos não estão no centro?", ["26", "24", "20", "27"], "Um único cubo (o centro) possui 0 faces pintadas. Portanto, 27 − 1 = 26 têm pelo menos uma face pintada."],
    "TSR3_02": ["Um cubo 3×3×3 é pintado em todas as faces e cortado em 27 cubos pequenos. Quantas faces unitárias pintadas todos os 27 cubos têm no total?", "Cada uma das 6 faces do cubo grande é uma grade 3×3, ou seja, 9 faces unitárias pintadas por face.", ["54", "48", "36", "27"], "6 faces × 9 = 54 faces unitárias pintadas."],
    "TSR3_03": ["O cubo 3×3×3 pintado é cortado em 27 cubos pequenos. Quantos cubos têm no máximo uma face pintada?", "Conte os cubos com 0 faces pintadas e exatamente 1 e depois some.", ["7", "6", "8", "12"], "1 cubo com 0 faces (o centro) + 6 cubos com exatamente 1 (os centros das faces). Total: 1 + 6 = 7."],
    "TSR3_04": ["O cubo 3×3×3 pintado é cortado em 27 cubos pequenos. Quantos cubos têm pelo menos 2 faces pintadas?", "São os cubos de canto (3 lados) e os de borda (2 lados).", ["20", "12", "8", "18"], "8 cantos (3 pintados) + 12 arestas × 1 cubo central de 2 lados = 20 cubos com 2 ou mais faces pintadas."],
    "TSR3_05": ["Se você cortar um cubo com um plano paralelo a uma das faces, qual será a forma da seção?", "Cortar paralelamente a uma face quadrada dá uma forma congruente a essa face.", ["Quadrado", "Retângulo", "Triângulo", "Hexágono"], "O plano paralelo a uma face corta quatro arestas iguais e dá um quadrado."],
    "TSR3_06": ["Se você cortar um cilindro com um plano perpendicular ao seu eixo, qual será a forma da seção?", "O eixo passa pelos centros das duas bases circulares.", ["Círculo", "Elipse", "Retângulo", "Oval"], "O corte perpendicular ao eixo é paralelo às bases – você obtém um círculo."],
    "TSR3_07": ["Se você cortar um cone com um plano paralelo à base circular, que formato obterá?", "A base do cone é um círculo. O corte paralelo dá uma forma semelhante.", ["Círculo", "Elipse", "Triângulo", "Parábola"], "O plano paralelo à base cruza o cone em um círculo (menor que a base)."],
    "TSR3_08": ["Quantos vértices uma esfera tem?", "O topo é onde as bordas se encontram. A esfera tem arestas?", ["0", "1", "2", "Infinito"], "A esfera é uma superfície lisa, sem arestas, portanto sem picos."],
    "TSR3_09": ["Quantas arestas uma esfera tem?", "A aresta é o segmento onde duas faces planas se encontram.", ["0", "1", "2", "Infinito"], "A esfera não possui faces planas, portanto não possui arestas."],
    "TSR3_10": ["Quantas faces tem uma pirâmide hexagonal?", "A pirâmide tem 1 base mais faces triangulares laterais – uma de cada lado da base.", ["7", "6", "8", "12"], "1 base hexagonal + 6 faces triangulares laterais = 7 faces."],
    "TSR3_11": ["Quantas arestas tem uma pirâmide hexagonal?", "Conte as arestas da base e as arestas de cada vértice da base até o vértice da pirâmide.", ["12", "6", "8", "18"], "6 arestas na base + 6 arestas laterais em direção ao topo = 12 arestas."],
    "TSR3_12": ["Quantos vértices tem uma pirâmide hexagonal?", "Conte os vértices da base e o único vértice superior.", ["7", "6", "8", "12"], "6 pontas na base + 1 ponta = 7 pontas. (Verificação de Euler: 7 − 12 + 7 = 2 ✓)"],
    "TSR3_13": ["Se você cortar um cubo do meio de uma aresta até o meio da aresta paralela oposta, que formato a seção pode ter?", "Cortar entre duas arestas paralelas resulta em um quadrilátero plano.", ["Retângulo", "Triângulo", "Pentágono", "Círculo"], "O plano por meio de duas arestas paralelas opostas dá uma seção retangular."],
    "TSR3_14": ["Quantas faces tem uma pirâmide de base pentagonal?", "1 base + faces laterais (uma por lado da base).", ["6", "5", "7", "10"], "1 base pentagonal + 5 faces triangulares = 6 faces."],
    "TSR3_15": ["Quantas arestas tem uma pirâmide com base pentagonal?", "Para pirâmide com base de n lados: 2n arestas.", ["10", "5", "8", "15"], "5 arestas na base + 5 lados = 10 arestas."],
    "TSR3_16": ["Quantos vértices tem uma pirâmide de base pentagonal?", "Os vértices da base mais o vértice superior.", ["6", "5", "7", "10"], "5 pontas na base + 1 ponta = 6 pontas. (Verifique: 6 − 10 + 6 = 2 ✓)"],
    "TSR3_17": ["Usando a fórmula de Euler (V − E + F = 2), se um poliedro tem 5 vértices e 8 arestas, quantas faces ele possui?", "Resolva para F: F = 2 − V + E.", ["5", "4", "6", "7"], "F = 2 − 5 + 8 = 5 (ex.: pirâmide de base quadrada: 5 vértices, 8 arestas, 5 faces)."],
    "TSR3_18": ["Quantas diagonais tem um hexágono regular?", "Para um polígono com n lados: n(n − 3) / 2.", ["9", "6", "12", "3"], "Diagonais = 6 × (6 - 3) / 2 = 9."],
    "TSR3_19": ["Em um cubo pintado 3×3×3 cortado em 27 cubos, quantas faces pintadas no total apenas os 8 cubos de canto têm?", "Cada cubo de canto tem exatamente 3 faces pintadas.", ["24", "8", "12", "18"], "8 cantos × 3 faces = 24 faces pintadas nos cantos."],
    "TSR3_20": ["Quantas diagonais tem um pentágono regular?", "Use n(n − 3) / 2 com n = 5.", ["5", "4", "6", "3"], "Diagonais = 5 × (5 − 3) / 2 = 5."],
    "TSR4_01": ["Um cubo 4×4×4 é pintado em todas as faces e depois cortado em 64 cubos pequenos. Quantos cubos têm pelo menos uma face pintada?", "O interior sem pintura forma um cubo menor com lado (4 − 2) = 2.", ["56", "48", "52", "60"], "Cubos com 0 tinta dentro = 2³ = 8. Com pelo menos 1 face pintada: 64 − 8 = 56."],
    "TSR4_02": ["O cubo 4×4×4 pintado é cortado em 64 cubos pequenos. Quantos cubos têm pelo menos 2 faces pintadas?", "Cubos de canto (3 lados) e cubos de borda (2 lados). Colete-os.", ["32", "24", "36", "28"], "Cantos: 8. Bordas: 12 × 2 cubos médios = 24. Total: 8 + 24 = 32."],
    "TSR4_03": ["O cubo 4×4×4 pintado é cortado em 64 cubos pequenos. Quantas faces unitárias pintadas todos os cubos têm no total?", "Cada uma das 6 faces do cubo grande é uma grade 4×4.", ["96", "64", "72", "108"], "6 × 16 = 96. (Verifique: 8 × 3 + 24 × 2 + 24 × 1 = 96 ✓)"],
    "TSR4_04": ["O cubo 4×4×4 pintado é cortado em 64 cubos pequenos. Quantos cubos têm no máximo uma face pintada?", "Adicione os cubos com 0 faces pintadas e exatamente 1.", ["32", "24", "28", "36"], "0 pintado: 8 (interior 2×2×2). 1 tingido: 24 (faces centrais). Total: 32."],
    "TSR4_05": ["Se você remover um cubo de canto de um cubo 3×3×3, quantas faces dos cubos unitários serão visíveis no sólido restante (incluindo a parte inferior)?", "Ao remover o canto você perde 3 faces externas, mas revela 3 faces internas anteriormente ocultas.", ["54", "51", "57", "48"], "Área inicial: 6 × 9 = 54. No canto: −3 fora + 3 recém-visíveis dentro = 0 rede. Eu permaneço com 54."],
    "TSR4_06": ["Quantas diagonais tem um octógono regular?", "Fórmula n(n − 3) / 2 com n = 8.", ["20", "16", "24", "8"], "Diagonais = 8 × 5/2 = 20."],
    "TSR4_07": ["Quantas diagonais espaciais um cubo tem? (A diagonal espacial passa pelo interior de um vértice ao vértice oposto.)", "O cubo tem 8 vértices. Cada diagonal espacial conecta um vértice ao seu oposto.", ["4", "6", "8", "12"], "O cubo tem 4 diagonais espaciais, cada uma passando pelo centro."],
    "TSR4_08": ["Quantas diagonais de face um cubo tem no total?", "Cada face é quadrada. Quantas diagonais tem o quadrado? Multiplique por 6.", ["12", "6", "8", "24"], "6 faces × 2 diagonais = 12 diagonais em faces."],
    "TSR4_09": ["Quantas faces tem um octaedro regular (duas pirâmides quadradas unidas na base)?", "Cada pirâmide traz 4 faces triangulares. A base quadrada comum está dentro.", ["8", "6", "12", "20"], "O octaedro regular possui 8 faces triangulares equiláteras."],
    "TSR4_10": ["Quantas arestas tem um octaedro regular?", "Use a fórmula de Euler se você conhece V = 6 e F = 8.", ["12", "8", "6", "24"], "E = V + F − 2 = 6 + 8 − 2 = 12 arestas."],
    "TSR4_11": ["Quantos vértices tem um octaedro regular?", "Pense em duas pirâmides unidas pela base. Conte os picos distintos.", ["6", "8", "12", "4"], "4 vértices ao redor do equador quadrado + 1 vértice para cima + 1 para baixo = 6."],
    "TSR4_12": ["Se 8 cubos unitários formam um cubo 2×2×2, quantas faces dos cubos unitários são visíveis do lado de fora (incluindo a parte inferior)?", "O resultado é um cubo com lado 2. Área total em faces unitárias?", ["24", "28", "32", "20"], "6 × (2×2) = 24 faces unitárias."],
    "TSR4_13": ["Um dodecaedro regular tem 12 faces pentagonais e 30 arestas. Com a fórmula de Euler, quantos vértices ele possui?", "V = 2 + E − F.", ["20", "12", "24", "30"], "V = 2 + 30 − 12 = 20 vértices."],
    "TSR4_14": ["Um icosaedro regular possui 20 faces triangulares e 12 vértices. Quantas arestas ele tem?", "E = V + F − 2.", ["30", "20", "24", "36"], "E = 12 + 20 − 2 = 30 arestas."],
    "TSR4_15": ["Em um cubo pintado 4×4×4, quantas faces pintadas os 8 cubos de canto têm no total?", "Qualquer cubo de canto tem exatamente 3 faces pintadas, independentemente do tamanho do cubo grande.", ["24", "8", "12", "32"], "8 × 3 = 24."],
    "TSR4_16": ["No mesmo cubo 4×4×4, quantas faces pintadas têm os cubos de arestas (aqueles com exatamente 2 faces pintadas)?", "Quantos cubos estão nas bordas e multiplique por 2.", ["48", "24", "36", "60"], "24 cubos nas arestas (12 arestas × 2), cada um com 2 faces pintadas: 24 × 2 = 48."],
    "TSR4_17": ["Se você cortar um cubo com um plano por meio de três arestas começando no mesmo vértice, qual será a forma da seção?", "As três médias são equidistantes do canto. Qual triângulo tem todos os lados iguais?", ["Triângulo Equilátero", "Quadrado", "Triângulo retângulo", "Hexágono regular"], "O avião corta as três arestas dos cantos igualmente – você obtém um triângulo equilátero."],
    "TSR4_18": ["Quantas diagonais tem um decágono regular (10 lados)?", "Fórmula: n(n − 3) / 2.", ["35", "30", "40", "25"], "10 × 7/2 = 35."],
    "TSR4_19": ["Um prisma tem exatamente 10 vértices. Qual é o formato da base?", "O prisma de base de n lados possui 2n vértices.", ["Pentágono", "Quadrado", "Hexágono", "Triângulo"], "2n = 10 → n = 5. A base é um pentágono."],
    "TSR4_20": ["Uma pirâmide tem exatamente 7 faces. Qual é o formato da base?", "A pirâmide base de n lados tem n + 1 faces.", ["Hexágono", "Pentágono", "Heptágono", "Octógono"], "n + 1 = 7 → n = 6. A base é um hexágono."],
    "TSR5_01": ["Um cubo 5×5×5 é pintado em todas as faces e depois cortado em 125 cubos pequenos. Quantos cubos têm exatamente 2 faces pintadas?", "Os cubos nas bordas (não nos cantos) têm 2 faces pintadas. Fórmula: 12(n − 2).", ["36", "24", "48", "30"], "12 × (5 − 2) = 36."],
    "TSR5_02": ["O cubo 5×5×5 pintado é cortado em 125 cubos pequenos. Quantos cubos têm exatamente 3 faces pintadas?", "Apenas os cubos de canto possuem 3 faces pintadas. Quantos cantos tem qualquer cubo?", ["8", "12", "20", "6"], "Qualquer cubo tem 8 cantos. Portanto, 8 cubos com exatamente 3 faces pintadas."],
    "TSR5_03": ["O cubo 5×5×5 pintado é cortado em 125 cubos pequenos. Quantos cubos têm pelo menos uma face pintada?", "Subtraia os cubos de dentro completamente sem pintura: (n − 2)³.", ["98", "96", "100", "90"], "Dentro = 3³ = 27. 125 − 27 = 98."],
    "TSR5_04": ["O cubo 5×5×5 pintado é cortado em 125 cubos pequenos. Quantas faces unitárias pintadas todos os cubos têm no total?", "Cada uma das 6 faces do cubo grande é uma grade 5×5.", ["150", "125", "144", "162"], "6 × 25 = 150."],
    "TSR5_05": ["Um cubo 6×6×6 pintado é cortado em 216 cubos pequenos. Quantos têm exatamente 2 faces pintadas?", "12(n − 2) com n = 6.", ["48", "36", "60", "24"], "12 × 4 = 48."],
    "TSR5_06": ["O cubo 6×6×6 pintado é cortado em 216 cubos pequenos. Quantos têm exatamente 1 rosto pintado?", "6(n − 2)² com n = 6.", ["96", "72", "108", "84"], "6 × 16 = 96."],
    "TSR5_07": ["O cubo 6×6×6 pintado é cortado em 216 cubos pequenos. Quantos não têm nenhuma pintura facial?", "Bloco interno: (n − 2)³.", ["64", "48", "36", "27"], "(6 − 2)³ = 64."],
    "TSR5_08": ["O cubo 6×6×6 pintado é cortado em 216 cubos pequenos. Quantos têm exatamente 3 faces pintadas?", "Os cantos são sempre 8, independente do tamanho.", ["8", "12", "6", "24"], "8 cubos com 3 faces pintadas. (Verifique: 8+48+96+64=216 ✓)"],
    "TSR5_09": ["O cubo 6×6×6 pintado é cortado em 216 cubos pequenos. Quantas faces unitárias pintadas eles têm no total?", "Cada face do cubo grande é uma grade 6×6.", ["216", "200", "192", "240"], "6 × 36 = 216."],
    "TSR5_10": ["Em um cubo pintado 10×10×10 cortado em 1000 cubos, quantas exatamente 2 faces pintadas existem?", "12(n − 2) para os cubos nas arestas.", ["96", "120", "80", "108"], "12 × 8 = 96."],
    "TSR5_11": ["No mesmo cubo 10×10×10, quantos cubos pequenos têm exatamente 1 face pintada?", "6(n − 2)² para os centros das faces.", ["384", "360", "400", "480"], "6 × 64 = 384."],
    "TSR5_12": ["Quantos cubos pequenos não têm rosto pintado?", "O interior é um cubo com lado (n − 2).", ["512", "480", "500", "343"], "(10 − 2)³ = 512."],
    "TSR5_13": ["Qual destas formas PODE ser a seção de um cubo?", "Um plano pode cruzar no máximo 6 faces. Você consegue passar por 6 arestas?", ["Hexágono regular", "Pentágono Regular", "Octógono regular", "Elipse"], "Por meio de 6 arestas você obtém um hexágono regular. A simetria do cubo não dá pentágonos, octógonos (máx. 6 lados) ou curvas."],
    "TSR5_14": ["Qual é o número máximo de lados de uma seção plana de um cubo?", "O polígono de seção ganha um lado para cada face que se cruza.", ["6", "4", "8", "12"], "O cubo tem 6 faces — no máximo hexágono (6 lados)."],
    "TSR5_15": ["O dodecaedro regular possui 12 faces pentagonais. Cada face possui 5 arestas, mas cada aresta é comum a 2 faces. Quantas arestas ele tem?", "12 × 5 lugares de borda, cada borda contada duas vezes.", ["30", "24", "36", "60"], "12 × 5/2 = 30 arestas."],
    "TSR5_16": ["Em um cubo pintado 7×7×7, cortado em 343 cubos, quantas exatamente 2 faces pintadas existem?", "12(n − 2) com n = 7.", ["60", "48", "72", "36"], "12 × 5 = 60."],
    "TSR5_17": ["No cubo 7×7×7, quantos cubos pequenos não têm a face pintada?", "(n − 2)³.", ["125", "64", "100", "27"], "5³ = 125."],
    "TSR5_18": ["Para o cubo pintado n×n×n, o número de cubos com exatamente 1 face pintada é 6(n − 2)². Por que há 96 na equação?", "6(n − 2)² = 96 → (n − 2)² = 16.", ["6", "5", "7", "8"], "n − 2 = 4 → n = 6."],
    "TSR5_19": ["Qual é o número máximo de lados de uma seção de um prisma triangular?", "O prisma triangular possui 5 faces (2 triângulos + 3 retângulos). Um plano pode cortar todos os 5?", ["5", "4", "3", "6"], "Um plano inclinado pode intersectar ambas as bases e as 3 faces laterais — secção pentagonal, máximo 5."],
    "TSR5_20": ["No cubo pintado 7×7×7, quantas faces unitárias pintadas os 343 cubos têm no total?", "Cada uma das 6 faces do cubo grande é uma grade 7×7.", ["294", "252", "300", "343"], "6 × 49 = 294."],
    "TMP1_1": ["Um fazendeiro tem 12 ovelhas. Todos, exceto 5, morrem. Quantas ovelhas sobraram?", "Concentre-se em \"todos menos 5\".", ["5", "7", "12", "0"], "\"Todos menos 5 morrem\" significa que 5 sobrevivem. A resposta é 5, não 12 menos 5."],
    "TMP1_2": ["Numa corrida você ultrapassa o terceiro colocado. Onde você está agora?", "O que acontece quando você ultrapassa alguém – você toma o lugar dele?", ["O 3º", "O 2º", "O 4º", "O 1º"], "Quando você ultrapassa a pessoa que está em 3º lugar, você ocupa o lugar dela – você se torna o 3º, não o 2º."],
    "TMP1_3": ["Quantos aniversários uma pessoa faz em média?", "Você nasce apenas uma vez.", ["1", "Cerca de 75", "365", "Depende da idade"], "Todo mundo faz aniversário apenas um dia – o dia em que nasceu. O resto são aniversários daquele dia."],
    "TMP1_4": ["Se você tem 5 laranjas e pega 2, quantas VOCÊ tem?", "Quem pegou as laranjas?", ["2", "3", "5", "0"], "Você pegou 2 laranjas, então você tem 2. A questão é quantas você tem, não quantas sobraram."],
    "TMP1_5": ["A é pai de B, mas B não é filho de A. Como isso é possível?", "Todas as variantes de gênero para B.", ["B é filha de A", "A não é realmente o pai de B", "B é adotado", "Eles são parentes adotivos"], "B é uma menina – ela é filha de A. Nem toda criança é menino."],
    "TMP1_6": ["Quantas vezes você pode subtrair 10 de 100?", "Após a primeira queda, sobraram 100?", ["1", "10", "9", "Do infinito"], "Apenas uma vez – depois disso você tem 90 e subtrai 10 de 90, não 100."],
    "TMP1_7": ["Se um galo põe ovos em cima do telhado, para que lado o ovo rola?", "O que exatamente é um galo?", ["Galos não põem ovos", "Esquerda", "Direita", "Permanece em cima"], "Os galos são machos e não põem ovos. A premissa é impossível."],
    "TMP1_8": ["O que pesa mais: meio quilo de penas ou meio quilo de tijolos?", "Observe atentamente a unidade de medida.", ["Da mesma forma", "Os tijolos", "Penas", "Depende"], "Uma libra é uma libra, independentemente do material. Ambos pesam exatamente meio quilo."],
    "TMP1_9": ["Uma camisa custava US$ 50 e tinha 50% de desconto. Quanto você paga?", "Calcula 50% do preço original.", ["US$ 25", "US$ 50", "US$ 30", "US$ 15"], "50% de $ 50 = $ 25."],
    "TMP1_10": ["Você está em um quarto escuro com uma vela, uma lamparina a óleo e uma lareira. Você tem apenas uma partida. O que você acende pela primeira vez?", "Você tem que acender alguma coisa antes de qualquer coisa.", ["A partida", "A vela", "A lâmpada", "A lareira"], "Primeiro você tem que acender o fósforo para poder acender o resto."],
    "TMP1_11": ["Um avião cai bem na fronteira de dois países. Onde você enterra os sobreviventes?", "Leia com atenção – quem estamos enterrando?", ["Não enterre os sobreviventes", "No país de partida", "No país de destino", "Na fronteira"], "Os sobreviventes estão vivos – não os enterre."],
    "TMP1_12": ["Quantos animais de cada espécie Moisés levou na arca?", "Verifique o nome na pergunta.", ["Nenhum - foi Noé, não Moisés", "2", "7", "1"], "Moisés não tinha uma arca – Noé tinha. A pergunta usa o nome errado para enganar você."],
    "TMP1_13": ["Existem 10 pássaros em cima do muro. Puxe um. Quantos ficaram em cima do muro?", "Como os outros reagem ao tiroteio?", ["0", "9", "10", "1"], "O barulho assusta a todos. Não sobrou nenhum."],
    "TMP1_14": ["Um fazendeiro tem 20 vacas. Todos, exceto 12, morrem. Quantos sobraram?", "\"Todos menos 12\".", ["12", "8", "20", "0"], "Eu sobrevivo aos 12."],
    "TMP1_15": ["O que sempre sobe e nunca desce?", "Algo que só cresce com o tempo.", ["Sua idade", "Um balão", "O sol", "A temperatura"], "A idade só aumenta."],
    "TMP1_16": ["Uma garota bate na bola a 3 m de distância. Volta para ela sem parede, sem outra pessoa, sem rotação. Como?", "De que maneira ele bateu nela?", ["Ele bateu nela verticalmente para cima", "O vento", "Ele pulou da árvore", "A inclinação"], "Ele a chutou; a gravidade o trouxe de volta."],
    "TMP1_17": ["O que tem cabeça e cauda, ​​mas não tem corpo?", "Objetos comuns, não animais.", ["Uma moeda", "Uma cobra", "Uma agulha", "Um cometa"], "A moeda tem face (cara) e cauda (cauda), sem corpo."],
    "TMP1_18": ["O médico lhe dá 5 comprimidos: um a cada hora. Quanto tempo leva o tratamento?", "Quando você toma seu primeiro comprimido?", ["4 horas", "5 horas", "6 horas", "3 horas"], "Hora 0, 1, 2, 3, 4 — as últimas 4 horas entre uma e cinco. Total de 4 horas desde o início."],
    "TMP1_19": ["Você tem uma tigela com 6 ovos e tira 2. Quantos você tem?", "Onde estão os ovos que você tirou?", ["2", "4", "6", "0"], "Você tirou 2 ovos, então você tem 2. Na tigela sobram 4, mas a pergunta é quantos você tem."],
    "TMP1_20": ["Um menino tem 4 anos e sua irmã tem metade da idade dele. Quando o menino completar 100 anos, quantos anos terá a irmã?", "A diferença de idade permanece a mesma.", ["98", "50", "100", "96"], "A irmã é 2 anos mais nova (4÷2=2). 100 − 2 = 98."],
    "TMP2_1": ["Uma caneta e um caderno juntos custam US$ 1,10. O caderno custa R$ 1,00 a mais que a caneta. Quanto custa a caneta?", "Seja x o preço da caneta; o caderno custa x + $ 1,00.", ["US$ 0,05", "US$ 0,10", "US$ 1,00", "US$ 0,50"], "x + (x + 1) = 1,10 → 2x = 0,10 → x = $ 0,05."],
    "TMP2_2": ["O médico lhe dá 3 comprimidos: um a cada 45 minutos. Quanto tempo leva?", "Quando você toma seu primeiro comprimido?", ["90 minutos", "135 minutos", "45 minutos", "120 minutos"], "Aos 0, 45 e 90 minutos – passam um total de 90 minutos."],
    "TMP2_3": ["5 trabalhadores constroem 5 paredes em 5 dias. Quanto tempo leva para 10 trabalhadores construir 10 paredes?", "Quanto custa um trabalhador para construir um muro?", ["5 dias", "10 dias", "2,5 dias", "1 dia"], "Cada um constrói 1 parede em 5 dias. 10 pessoas, 10 paredes paralelas — também 5 dias."],
    "TMP2_4": ["Duas moedas equivalem a 30 centavos. Um não é um níquel (5 centavos). Quais são as moedas?", "“Um não é um níquel” – qual é o outro?", ["25 ¢ e 5 ¢ (trimestre + níquel)", "Duas moedas de 10 centavos", "50 centavos", "10¢ e 5¢"], "Um custa um quarto (25 centavos), não um níquel; o outro é o níquel (5¢). Total 30 centavos."],
    "TMP2_5": ["Multiplique todos os dígitos no teclado do telefone (0–9). Qual é o produto?", "O que acontece quando você multiplica por um determinado número?", ["0", "3.628.800", "362.880", "45"], "Entre os números está 0. Qualquer produto que inclua 0 é 0."],
    "TMP2_6": ["Uma família tem 4 meninos e 3 meninas. Todo menino tem tantas irmãs quanto irmãos. Cada menina tem o dobro de irmãos do que irmãs. Quantas crianças existem?", "Conte da perspectiva de cada criança.", ["7", "8", "6", "10"], "Menino: 3 irmãos, 3 irmãs✓. Menina: 4 irmãos, 2 irmãs (4 = 2×2) ✓. Total 7."],
    "TMP2_7": ["Um trem elétrico vai para o norte. O vento sopra do oeste. Para onde vai a fumaça?", "Que tipo de propulsão o trem tem?", ["Não há fumaça", "Oeste", "Norte", "Estimativa"], "O trem elétrico não queima combustível – não tem fumaça."],
    "TMP2_8": ["8 pessoas constroem um muro em 10 horas. Quanto tempo leva com 4 pessoas?", "Metade das pessoas dobra o tempo.", ["20 horas", "5 horas", "40 horas", "10 horas"], "10 × 2 = 20 horas."],
    "TMP2_9": ["Quantos meses do ano têm (pelo menos) 30 dias?", "Alguns meses têm mais de 30 dias.", ["11", "4", "6", "7"], "Todos os meses têm pelo menos 30 dias, exceto fevereiro. Então, 11 meses."],
    "TMP2_10": ["Cave 6 buracos: 3 grandes e 3 pequenos. quantos buracos você tem", "O tamanho altera o fato de ser um buraco?", ["6", "3", "9", "0"], "Todos os 6 buracos."],
    "TMP2_11": ["Você consegue citar três dias consecutivos sem segunda, terça, quarta, quinta, sexta, sábado, domingo?", "Termos relativos, não nomes próprios.", ["Ontem, hoje e amanhã", "Dia 1, 2, 3", "Impossível", "Manhã, meio-dia, noite"], "Ontem, hoje, amanhã são sempre três dias consecutivos."],
    "TMP2_12": ["Quanto é 1/2 de 2/3 de 3/4 de 4/5 de 100?", "Simplifique as frações antes da multiplicação.", ["20", "10", "50", "25"], "1/2 × 2/3 × 3/4 × 4/5 = 1/5. 1/5 × 100 = 20."],
    "TMP2_13": ["Um nenúfar dobra sua superfície todos os dias. No dia 20, encha o lago. Em que dia cobriu exatamente 25%?", "Volte ao contrário: divida por 2 todos os dias.", ["Dia 18", "Dia 5", "Dia 15", "Dia 10"], "Dia 20: 100%. Dia 19: 50%. Dia 18: 25%."],
    "TMP2_14": ["Um tijolo pesa 1 kg mais metade do peso do tijolo. Quanto pesa?", "Seja b o peso: b = 1 + b/2.", ["2kg", "1,5kg", "3kg", "1kg"], "b/2 = 1 → b = 2 kg."],
    "TMP2_15": ["6 homens cavam 6 buracos em 6 horas. Quanto tempo leva para 3 pessoas cavarem 3 buracos?", "Quanto tempo leva um buraco para uma pessoa?", ["6 horas", "3 horas", "12 horas", "9 horas"], "Cada um cava 1 buraco em 6 horas. 3 pessoas, 3 buracos em paralelo – também 6 horas."],
    "TMP2_16": ["Qual é a próxima letra: O, T, T, F, F, S, S, ?", "Em inglês: as iniciais dos números Um, Dois, Três…", ["E", "N", "T", "H"], "Um, Dois, Três, Quatro, Cinco, Seis, Sete, Oito → O, T, T, F, F, S, S, E."],
    "TMP2_17": ["Você tem 8 bolas: 7 iguais, uma mais pesada. Com uma balança, quantas pesagens mínimas para encontrá-la?", "Divida em três grupos, não em dois.", ["2", "3", "1", "4"], "3 contra 3; depois 1 contra 1 ou do grupo difícil. Máximo 2 pesagens."],
    "TMP2_18": ["Em uma corrida você ultrapassa o último. Em que assento você está?", "Quem está por trás do último?", ["É impossível", "O último", "O penúltimo", "O primeiro"], "Não há ninguém atrás do último – você não pode estar atrás dele para vencê-lo."],
    "TMP2_19": ["3 gatos pegam 3 ratos em 3 minutos. Quanto tempo leva para 100 gatos pegarem 100 ratos?", "Quantos minutos um gato pega um rato?", ["3 minutos", "100 minutos", "33 minutos", "1 minuto"], "Cada um pega 1 rato em 3 minutos. Paralelamente — também 3 minutos."],
    "TMP2_20": ["Que fração do dia equivale a 6 horas?", "Quantas horas há no dia?", ["1/4", "1/6", "1/3", "1/2"], "24/06 = 1/4."],
    "TMP3_1": ["6 máquinas fazem 6 brinquedos em 6 minutos. Quanto tempo leva para 12 máquinas fazerem 12 brinquedos?", "Quantos minutos uma máquina faz um brinquedo?", ["6 minutos", "12 minutos", "3 minutos", "1 minuto"], "Cada um faz 1 brinquedo em 6 minutos. 12 carros em paralelo – também 6 minutos."],
    "TMP3_2": ["O relógio marca 6:00. Qual é o ângulo entre o ponteiro das horas e o ponteiro dos minutos?", "Para onde apontam as línguas às 18h em ponto?", ["180°", "90°", "120°", "360°"], "Ponteiro dos minutos às 12, ponteiro das horas às 6 — linha reta, 180°."],
    "TMP3_3": ["O relógio marca 9:00. Qual é o ângulo entre as línguas?", "Para onde olham as línguas às 9h em ponto?", ["90°", "180°", "270°", "45°"], "Ponteiro dos minutos às 12, ponteiro das horas às 9 — ângulo reto, 90°."],
    "TMP3_4": ["Em uma grade, coluna 1 + coluna 2 = coluna 3. Linhas: [3, 5, 8], [7, 2, 9], [4, 6, ?]. Encontre o número que falta.", "Aplique a mesma regra à terceira linha.", ["10", "8", "12", "6"], "4 + 6 = 10."],
    "TMP3_5": ["Em uma grade, coluna 1 × coluna 2 = coluna 3. Linhas: [2, 5, 10], [3, 4, 12], [6, 3, ?]. Encontre o número que falta.", "Multiplique as duas primeiras colunas da terceira linha.", ["18", "9", "15", "21"], "6 × 3 = 18."],
    "TMP3_6": ["Um caracol sobe 4 m durante o dia e desliza 2 m à noite. A parede tem 12 m. Quantos dias leva para chegar ao topo?", "No último dia ele poderá sair antes de voltar.", ["5 dias", "6 dias", "4 dias", "10 dias"], "Líquido +2 m por ciclo. Após 4 dias: 8 m. No 5º dia suba 8+4=12 m — chegue antes do anoitecer."],
    "TMP3_7": ["2 pessoas pintam 2 quartos em 2 horas. Quanto tempo demora com 4 pessoas e 4 quartos?", "Quantas horas um homem pinta um quarto?", ["2 horas", "4 horas", "1 hora", "8 horas"], "Cada um pinta 1 cômodo em 2 horas. 4 pessoas, 4 câmeras em paralelo — também 2 horas."],
    "TMP3_8": ["Você compra algo por US$ 3 e vende por US$ 5. Então você compra outra coisa por US$ 6 e vende por US$ 9. Qual é o lucro total?", "O lucro de cada transação separadamente.", ["US$ 5", "US$ 3", "US$ 2", "US$ 6"], "5−3=2, 9−6=3. Total $ 5."],
    "TMP3_9": ["Um sapo salta 3 m para frente e desliza 1 m para trás por ciclo. Quantos saltos até ultrapassar 10 m?", "O último salto pode ser sem retrocesso.", ["5 saltos", "4 saltos", "6 saltos", "10 saltos"], "Após 4 ciclos: 8 m. 5º salto: 8+3=11 m > 10. Então 5."],
    "TMP3_10": ["Tom tem três vezes a idade de Jim. Em 10 anos, Tom terá o dobro da idade de Jim. Quantos anos Jim tem agora?", "T=3J; T+10 = 2(D+10).", ["10", "5", "15", "20"], "3J+10 = 2J+20 → J = 10."],
    "TMP3_11": ["Você compra um cavalo por US$ 60, vende-o por US$ 70, compra-o de volta por US$ 80 e vende-o por US$ 90. Lucro total?", "Cada transação separadamente.", ["US$ 20", "US$ 10", "US$ 30", "US$ 0"], "+$10 então +$10 = $20."],
    "TMP3_12": ["Você dobra uma folha ao meio 7 vezes. Quantas camadas?", "Cada dobra duplica as camadas.", ["128", "64", "14", "256"], "2⁷ = 128."],
    "TMP3_13": ["Um número primo multiplicado por ele mesmo dá 169. Qual é o número?", "A raiz quadrada de 169.", ["13", "11", "17", "7"], "√169 = 13, que é primo."],
    "TMP3_14": ["Dois trens estão separados por 160 quilômetros, cada um indo em direção ao outro a 80 quilômetros por hora. Uma mosca voa a 120 km/h entre eles. Quanto tempo até os trens se encontrarem?", "Quanto tempo até eles se conhecerem?", ["75 milhas", "100 milhas", "50 milhas", "150 milhas"], "Velocidade relativa 160 km/h → 1 hora. Voar: 75 × 1 = 75 milhas."],
    "TMP3_15": ["Qual é o menor número divisível por todos os 1, 2, 3, 4, 5 e 6?", "Mínimo Múltiplo Comum (CMMMC).", ["60", "30", "120", "720"], "CMMMC(1…6) = 60."],
    "TMP3_16": ["Contando de 1 a 100, quantas vezes aparece o número 7?", "Unidades e dezenas separadamente.", ["20", "10", "11", "19"], "Unidades: 7,17,…,97 — 10. Dezenas: 70–79 — 10. Total 20."],
    "TMP3_17": ["Um número aumenta 20% e passa a ser 60. Qual era originalmente?", "1,2x = 60.", ["50", "48", "72", "40"], "x = 60 / 1,2 = 50."],
    "TMP3_18": ["Você dobra uma folha ao meio 10 vezes. Quantas camadas?", "Cada dobra dobra.", ["1024", "100", "512", "2048"], "2¹⁰ = 1024."],
    "TMP3_19": ["O produto de dois números inteiros positivos consecutivos é 156. O que são?", "Dois números consecutivos cujo produto é 156.", ["12 e 13", "11 e 12", "13 e 14", "10 e 15"], "12 × 13 = 156."],
    "TMP3_20": ["Quadrado mágico 3×3: cada linha, coluna e diagonal somam 15. Primeira linha [2, 7, 6], meio [9, 5, 1]. Qual é o primeiro número da última linha?", "A primeira coluna também soma 15.", ["4", "3", "6", "8"], "2+9+? = 15 → ? = 4."],
    "TMP4_1": ["Uma colônia de bactérias dobra a cada hora e enche completamente uma jarra ao meio-dia. A que horas estava a jarra de um quarto?", "Volte: divida por 2 a cada hora.", ["10:00", "11:00", "9h00", "6:00"], "Meio-dia: 100%. 11h: 50%. 10h00: 25%."],
    "TMP4_2": ["Você tem 24 moedas; um é falso e mais fácil. Quantas pesagens mínimas em uma balança para ter certeza?", "Divida em três grupos em cada etapa.", ["3", "4", "5", "2"], "8 x 8, depois no grupo leve 3 x 3, depois 1 x 1 – 3 pesagens."],
    "TMP4_3": ["Uma corda é cortada em 3 pedaços. Cada pedaço é cortado em 3 pedaços menores. Quantas peças no total?", "3×3.", ["9", "6", "12", "27"], "3 × 3 = 9."],
    "TMP4_4": ["Uma minhoca está no fundo de um poço de 30 m. Sobe 5 m durante o dia e desliza 4 m à noite. Quantos dias sai?", "No último dia sai sem escorregar.", ["26 dias", "30 dias", "25 dias", "27 dias"], "Líquido +1 m/dia. Após 25 dias: 25 m. Dia 26: 25+5=30 m."],
    "TMP4_5": ["8 homens constroem um muro em 10 dias. Quantos dias com 5 homens?", "Trabalho total = pessoas × dias.", ["16 dias", "12 dias", "20 dias", "8 dias"], "8×10 = 80 dias-homem. 80/5 = 16 dias."],
    "TMP4_6": ["Os tubos A e B enchem um tanque em 6 horas e 3 horas, respectivamente. Quanto tempo ambos permanecem abertos?", "Adiciona os fluxos: 1/6 + 1/3 por hora.", ["2 horas", "4,5 horas", "3 horas", "1,5 horas"], "1/6+2/6=1/2 por hora → 2 horas."],
    "TMP4_7": ["Um retângulo tem 3 vezes mais comprimento do que largura. O perímetro é de 48 m. Qual é a área?", "eu = 3w; 2(w+3w)=48.", ["108 m²", "96 m²", "144 m²", "48 m²"], "8w=48 → w=6, l=18, área 108 m²."],
    "TMP4_8": ["Um número aumenta 20% e depois diminui 20%. Qual é a variação líquida do original?", "Aplique as porcentagens uma de cada vez.", ["Redução de 4%", "0%", "Aumento de 4%", "2% de desconto"], "100→120→96. -4% líquido."],
    "TMP4_9": ["A loja aumenta os preços em 25% e depois dá descontos em 20%. A mudança líquida?", "1,25 × 0,80.", ["0% (sem alteração)", "+5%", "-5%", "+45%"], "1,25 × 0,80 = 1 – no lugar."],
    "TMP4_10": ["A soma dos primeiros 20 números naturais positivos?", "n(n+1)/2.", ["210", "200", "190", "220"], "20×21/2 = 210."],
    "TMP4_11": ["O ângulo entre os ponteiros do relógio às 4h30?", "O horário é entre quatro e meia e cinco.", ["45°", "90°", "60°", "30°"], "Minuto 180°, horário 135°, diferença 45°."],
    "TMP4_12": ["O carro percorre 60 km a 30 km/h, depois 60 km a 60 km/h. Velocidade média?", "Distância total/tempo total.", ["40 km/h", "45 km/h", "50 km/h", "35 km/h"], "2h + 1h = 3h; 120/3 = 40km/h."],
    "TMP4_13": ["Se 2¹⁰ = 1024, quanto é 2¹²?", "2¹⁰ × 2².", ["4096", "2048", "8192", "1248"], "1024 × 4 = 4096."],
    "TMP4_14": ["Uma torneira enche a piscina em 4 horas; o dreno o limpa em 8 horas. quanto tempo leva para preencher com os dois abertos?", "Fluxo líquido = enchimento - esvaziamento.", ["8 horas", "6 horas", "12 horas", "4 horas"], "1/4 - 1/8 = 1/8 por hora → 8 horas."],
    "TMP4_15": ["O preço cai 10%, depois mais 10%. A queda total do original?", "Os segundos 10% incidem sobre o preço já reduzido.", ["19%", "20%", "18%", "21%"], "0,9×0,9=0,81 → redução de 19%."],
    "TMP4_16": ["Encontre x: 3x + 7 = 22.", "Isole x.", ["5", "7", "3", "10"], "3x=15→x=5."],
    "TMP4_17": ["Um trem de 100 m viaja a 50 m/s. Quanto tempo eles levam para passar completamente por um poste?", "O comprimento do trem deve ser coberto.", ["2 segundos", "1 segundo", "4 segundos", "0,5 segundos"], "100/50 = 2s."],
    "TMP4_18": ["Doi muncitori termina o lucro em 12 anos. Um em 20 dias. Cât îi ia celuilalt singur?", "12/01 - 20/01.", ["30 dias", "24 dias", "15 dias", "40 dias"], "1/30 por dia → 30 dias."],
    "TMP4_19": ["Você investe $ 1.000 com juros simples de 5% ao ano, 3 anos. Quanto de juros total?", "Juros simples = capital × taxa × tempo.", ["US$ 150", "US$ 1.150", "US$ 50", "US$ 300"], "1000 × 0,05 × 3 = $ 150."],
    "TMP4_20": ["O fazendeiro tem galinhas e vacas. 20 cabeças e 56 pés. quantas galinhas", "g + v = 20; 2g + 4v = 56.", ["12", "8", "14", "10"], "v=8, g=12."],
    "TMP5_1": ["Você tem duas cordas; cada um queima completamente em exatamente 1 hora, mas de forma irregular. Como você mede exatamente 45 minutos?", "O que acontece se você acender uma corda nas duas pontas?", ["Você acende a corda 1 em ambas as extremidades e a corda 2 em uma extremidade, simultaneamente", "Você acende as duas cordas em uma extremidade", "Corte uma corda em quatro e acenda um pedaço", "Você acende uma corda, espera queimar, depois a outra"], "A corda 1 (ambas as pontas) queima em 30 min. Em seguida, acenda a outra ponta da corda 2 – mais 15 min. Total: 45 minutos."],
    "TMP5_2": ["Dois pais e dois filhos estão comendo. Coma exatamente 3 ovos, um de cada. Como isso é possível?", "Uma pessoa pode desempenhar duas funções?", ["Avô, pai e filho (3 pessoas)", "Um não comeu", "Eram 4, mas os ovos foram compartilhados", "Alguém comeu dois ovos"], "Três gerações: avô (pai), pai (e filho e pai), filho. Dois pais + dois filhos = 3 pessoas."],
    "TMP5_3": ["100 armários seguidos, todos trancados. O aluno k troca cada k-ésimo armário. Quantos ficam abertos no final?", "Um gabinete está aberto se for comutado um número ímpar de vezes. Quais números têm um número ímpar de divisores?", ["10", "50", "25", "0"], "Apenas quadrados perfeitos: 1, 4, 9, 16, 25, 36, 49, 64, 81, 100 — 10 gabinetes."],
    "TMP5_4": ["Três interruptores fora de uma sala fechada controlam três lâmpadas dentro dela. Você pode entrar apenas uma vez. Como você descobre quem é quem?", "Uma lâmpada acesa por muito tempo permanece quente mesmo depois de desligada.", ["Ligue 1, espere, desligue; 2 LIGADO; digite: quente desligado = 1, ligado = 2, frio desligado = 3", "Troque um de cada vez e verifique cada vez", "Você liga e desliga rapidamente todos os três e entra", "Você olha para o buraco da fechadura após cada troca"], "1 ON por alguns minutos, OFF, 2 ON, entre. Quente desligado = 1. Ligado = 2. Frio desligado = 3."],
    "TMP5_5": ["Três caixas marcadas como \"Maçãs\", \"Laranjas\", \"Mistura\". Todos os rótulos estão errados. Você pode tirar uma fruta de uma caixa. De qual?", "A caixa «Mistura» não pode conter mistura, se todos os rótulos forem falsos.", ["Caixa \"misturar\"", "Caixa \"maçã\"", "Caixa \"Laranjas\"", "Qualquer caixa"], "Pegue na caixa «Mistura»: o conteúdo é só de um tipo. Conforme a fruta, deduz o resto; os rótulos «Maçãs» e «Laranjas» estão todos errados."],
    "TMP5_6": ["Um homem tem três filhas. O produto das idades é 36. A soma é o número da casa vizinha (ambígua). O mais velho toca piano. Quais são as idades?", "Dois trigêmeos de divisores de 36 têm a mesma soma. \"Maior\" elimina um caso.", ["2, 2 e 9", "1, 6 e 6", "3, 3 e 4", "1, 4 e 9"], "Soma 13: {1,6,6} e {2,2,9}. Existe um único «maior» → {2, 2, 9}."],
    "TMP5_7": ["O problema de Monty Hall: você escolhe a porta 1 de 3 (um carro, duas cabras). O anfitrião abre a porta 3 – cabra. Você troca na porta 2?", "Qual foi a probabilidade inicial para sua porta?", ["Sim – a mudança vence 2/3 das vezes", "Não - é 50/50", "Não importa", "Não – a primeira escolha geralmente é correta"], "Sua escolha: 1/3. A porta restante é 2/3. A mudança dobra as chances."],
    "TMP5_8": ["Quantos quadrados de qualquer tamanho há em um tabuleiro de xadrez 8×8?", "Conte separadamente 1×1, 2×2,… 8×8.", ["204", "64", "256", "100"], "8²+7²+…+1² = 204."],
    "TMP5_9": ["A soma dos números de 1 a 100?", "Fórmula de Gauss: n(n+1)/2.", ["5050", "5.000", "10.000", "10100"], "100×101/2 = 5050."],
    "TMP5_10": ["Quantos zeros no final de 100!?", "Os zeros vêm dos fatores 10 = 2×5. Conte as potências de 5.", ["24", "20", "25", "10"], "⌊100/5⌋ + ⌊100/25⌋ = 24."],
    "TMP5_11": ["O fazendeiro atravessa o rio com o lobo, a cabra e o repolho. Barco: fazendeiro + um item. O lobo come a cabra deixada sozinha; a cabra come o repolho. Com o que começa?", "Qual par você pode deixar sozinho na praia?", ["Cabra", "O lobo", "Repolho", "Não importa"], "Primeiro a cabra. O lobo e o repolho estão seguros. Depois o resto com turnos."],
    "TMP5_12": ["A partir de um par de coelhos, eles amadurecem em 1 mês e produzem um novo par mensalmente após a maturidade. Quantos pares após 6 meses?", "Sequência de Fibonacci: 1, 1, 2, 3, 5, 8,…", ["8", "13", "6", "10"], "Mês 1–6: 1, 1, 2, 3, 5, 8 pares."],
    "TMP5_13": ["Número mínimo de movimentos nas Torres de Hanói com 5 discos?", "2ⁿ − 1, n = número de discos.", ["31", "32", "63", "15"], "2⁵ − 1 = 31."],
    "TMP5_14": ["Número mínimo de pessoas em uma sala tal que haja >50% de probabilidade de que duas façam aniversário no mesmo dia?", "O paradoxo do aniversário – a resposta é menos do que aparenta.", ["23", "50", "183", "365"], "Em 23 pessoas, a probabilidade ultrapassa 50%."],
    "TMP5_15": ["Numa sala com 23 pessoas, qual é a probabilidade aproximada de pelo menos duas fazerem aniversário no mesmo dia?", "O resultado do paradoxo do aniversário.", ["cerca de 50%", "cerca de 6%", "cerca de 25%", "cerca de 75%"], "Com 23 pessoas, ~50,7%."],
    "TMP5_16": ["Numa ilha, os cavaleiros dizem a verdade, os bandidos mentem. Para dizer: \"Nós dois somos bandidos.\" O que é A?", "Se A fosse um cavaleiro, a afirmação poderia ser verdadeira?", ["Golpista", "Cavaleiro", "Não pode ser determinado", "Nenhum"], "Um cavaleiro não poderia dizer “ambos vigaristas”. Então A mente; a afirmação é falsa – ambos não são bandidos, o outro é um cavaleiro."],
    "TMP5_17": ["A soma dos ângulos internos de um heptágono (7 lados)?", "(n − 2) × 180°.", ["900°", "720°", "1080°", "1260°"], "5 × 180° = 900°."],
    "TMP5_18": ["Quantos quadrados de qualquer tamanho há em uma grade 4×4?", "1×1, 2×2, 3×3, 4×4.", ["30", "16", "20", "25"], "4²+3²+2²+1² = 30."],
    "TMP5_19": ["Você joga uma moeda honesta 3 vezes. A probabilidade de aparecer pelo menos uma vez «cabeça»?", "O complemento: nunca cabeça (página três vezes).", ["7/8", "3/4", "1/2", "1/8"], "P(sem cabeça) = (1/2)³ = 1/8. P(pelo menos uma cabeça) = 7/8."],
    "TMP5_20": ["Quantos retângulos nas linhas de uma grade 3×3 (4 horizontais, 4 verticais)?", "Você escolhe 2 horizontais e 2 verticais.", ["36", "18", "24", "9"], "C(4,2)² = 36."],
  }
});
